     1→/**
     2→ * MMS Baseline Assumption Service
     3→ *
     4→ * Manages PM history assumptions for cold start scenarios during data migration.
     5→ * Implements inference rules, manual review queue, and approval workflow.
     6→ *
     7→ * Key features:
     8→ * - Inference rules for missing PM history (from commissioning, higher PM, etc.)
     9→ * - Manual review queue for LOW/ESTIMATED confidence assumptions
    10→ * - Review/approval workflow with audit trail
    11→ * - Integration with PM scheduler for baseline calculation
    12→ *
    13→ * @see specs/003-database-schema.md Section 3.2.6
    14→ * @see ADR-014: PM History Assumptions for Cold Start
    15→ */
    16→
    17→import { eq, and, inArray, isNull, desc, asc, sql, count, SQL } from 'drizzle-orm';
    18→import { BaseService, MmsAttributes, type Span } from '../lib/services/base';
    19→import {
    20→  pmBaselineAssumptions,
    21→  trains,
    22→  pmTypes,
    23→  pmSchedule,
    24→  users,
    25→  type PmBaselineAssumption,
    26→  type NewPmBaselineAssumption,
    27→  type Train,
    28→  type PmType,
    29→} from '../lib/db/schema';
    30→import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';
    31→import { addDays, addMonths, differenceInDays, parseISO, format } from 'date-fns';
    32→
    33→// =============================================================================
    34→// Types
    35→// =============================================================================
    36→
    37→/** Assumption type for PM history inference */
    38→export type AssumptionType =
    39→  | 'INFERRED_FROM_COMMISSIONING'
    40→  | 'INFERRED_FROM_HIGHER_PM'
    41→  | 'MANUAL_OVERRIDE'
    42→  | 'IMPORTED'
    43→  | 'NO_HISTORY';
    44→
    45→/** Confidence level for assumption quality */
    46→export type ConfidenceLevel = 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';
    47→
    48→/** Review status for assumptions */
    49→export type ReviewStatus = 'PENDING_REVIEW' | 'REVIEWED' | 'APPLIED' | 'REJECTED';
    50→
    51→/** PM hierarchy mapping - higher PMs satisfy lower ones */
    52→const PM_HIERARCHY: Record<string, string[]> = {
    53→  OVERHAUL: ['C4', 'C3', 'C2', 'C1'],
    54→  C4: ['C3', 'C2', 'C1'],
    55→  C3: ['C2', 'C1'],
    56→  C2: ['C1'],
    57→  C1: [],
    58→};
    59→
    60→/** Default PM intervals in months */
    61→const DEFAULT_PM_INTERVALS: Record<string, number> = {
    62→  C1: 6,
    63→  C2: 12,
    64→  C3: 24,
    65→  C4: 48,
    66→  OVERHAUL: 96,
    67→};
    68→
    69→/** Request to create a new assumption */
    70→export interface CreateAssumptionRequest {
    71→  trainId: string;
    72→  pmTypeId: string;
    73→  assumptionType: AssumptionType;
    74→  assumedLastPmDate?: string; // ISO date
    75→  assumedLastPmMileage?: number;
    76→  confidenceLevel: ConfidenceLevel;
    77→  inferenceSource?: string;
    78→  inferenceData?: Record<string, unknown>;
    79→  requiresReview?: boolean;
    80→}
    81→
    82→/** Request to update an assumption */
    83→export interface UpdateAssumptionRequest {
    84→  assumedLastPmDate?: string;
    85→  assumedLastPmMileage?: number;
    86→  confidenceLevel?: ConfidenceLevel;
    87→  inferenceSource?: string;
    88→  inferenceData?: Record<string, unknown>;
    89→  requiresReview?: boolean;
    90→}
    91→
    92→/** Request to review an assumption */
    93→export interface ReviewAssumptionRequest {
    94→  reviewNotes?: string;
    95→  approved: boolean;
    96→  /** If approved=false and corrections provided, update the assumption */
    97→  correctedDate?: string;
    98→  correctedMileage?: number;
    99→}
   100→
   101→/** Request to apply an assumption to the PM schedule */
   102→export interface ApplyAssumptionRequest {
   103→  /** Override the assumed values if needed */
   104→  overrideDate?: string;
   105→  overrideMileage?: number;
   106→}
   107→
   108→/** Request to infer assumptions from commissioning date */
   109→export interface InferFromCommissioningRequest {
