/**
 * MMS Baseline Assumption Service
 *
 * Manages PM history assumptions for cold start scenarios during data migration.
 * Implements inference rules, manual review queue, and approval workflow.
 *
 * Key features:
 * - Inference rules for missing PM history (from commissioning, higher PM, etc.)
 * - Manual review queue for LOW/ESTIMATED confidence assumptions
 * - Review/approval workflow with audit trail
 * - Integration with PM scheduler for baseline calculation
 *
 * @see specs/003-database-schema.md Section 3.2.6
 * @see ADR-014: PM History Assumptions for Cold Start
 */

import { eq, and, inArray, isNull, desc, asc, sql, count, SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes, type Span } from '../lib/services/base';
import {
  pmBaselineAssumptions,
  trains,
  pmTypes,
  pmSchedule,
  users,
  type PmBaselineAssumption,
  type NewPmBaselineAssumption,
  type Train,
  type PmType,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';
import { addDays, addMonths, differenceInDays, parseISO, format } from 'date-fns';

// =============================================================================
// Types
// =============================================================================

/** Assumption type for PM history inference */
export type AssumptionType =
  | 'INFERRED_FROM_COMMISSIONING'
  | 'INFERRED_FROM_HIGHER_PM'
  | 'MANUAL_OVERRIDE'
  | 'IMPORTED'
  | 'NO_HISTORY';

/** Confidence level for assumption quality */
export type ConfidenceLevel = 'HIGH' | 'MEDIUM' | 'LOW' | 'ESTIMATED';

/** Review status for assumptions */
export type ReviewStatus = 'PENDING_REVIEW' | 'REVIEWED' | 'APPLIED' | 'REJECTED';

/** PM hierarchy mapping - higher PMs satisfy lower ones */
const PM_HIERARCHY: Record<string, string[]> = {
  OVERHAUL: ['C4', 'C3', 'C2', 'C1'],
  C4: ['C3', 'C2', 'C1'],
  C3: ['C2', 'C1'],
  C2: ['C1'],
  C1: [],
};

/** Default PM intervals in months */
const DEFAULT_PM_INTERVALS: Record<string, number> = {
  C1: 6,
  C2: 12,
  C3: 24,
  C4: 48,
  OVERHAUL: 96,
};

/** Request to create a new assumption */
export interface CreateAssumptionRequest {
  trainId: string;
  pmTypeId: string;
  assumptionType: AssumptionType;
  assumedLastPmDate?: string; // ISO date
  assumedLastPmMileage?: number;
  confidenceLevel: ConfidenceLevel;
  inferenceSource?: string;
  inferenceData?: Record<string, unknown>;
  requiresReview?: boolean;
}

/** Request to update an assumption */
export interface UpdateAssumptionRequest {
  assumedLastPmDate?: string;
  assumedLastPmMileage?: number;
  confidenceLevel?: ConfidenceLevel;
  inferenceSource?: string;
  inferenceData?: Record<string, unknown>;
  requiresReview?: boolean;
}

/** Request to review an assumption */
export interface ReviewAssumptionRequest {
  reviewNotes?: string;
  approved: boolean;
  /** If approved=false and corrections provided, update the assumption */
  correctedDate?: string;
  correctedMileage?: number;
}

/** Request to apply an assumption to the PM schedule */
export interface ApplyAssumptionRequest {
  /** Override the assumed values if needed */
  overrideDate?: string;
  overrideMileage?: number;
}

/** Request to infer assumptions from commissioning date */
export interface InferFromCommissioningRequest {
  trainId: string;
  /** PM type codes to generate assumptions for */
  pmTypeCodes?: string[];
}

/** Request to infer assumptions from higher PM */
export interface InferFromHigherPmRequest {
  trainId: string;
  /** Known PM type code (e.g., C4) */
  knownPmTypeCode: string;
  /** Date of the known PM */
  knownPmDate: string;
  /** Mileage at the known PM */
  knownPmMileage: number;
}

/** Filters for querying assumptions */
export interface AssumptionFilters {
  trainId?: string;
  pmTypeId?: string;
  confidenceLevel?: ConfidenceLevel | ConfidenceLevel[];
  assumptionType?: AssumptionType | AssumptionType[];
  requiresReview?: boolean;
  reviewed?: boolean;
  applied?: boolean;
}

/** Pagination options */
export interface PaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: 'createdAt' | 'confidenceLevel' | 'trainNumber';
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result */
export interface PaginatedResult<T> {
  items: T[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Assumption with related data */
export interface AssumptionWithDetails extends PmBaselineAssumption {
  train: Pick<Train, 'id' | 'trainNumber' | 'currentMileageKm' | 'commissioningDate'>;
  pmType: Pick<PmType, 'id' | 'pmCode' | 'intervalKm' | 'intervalMonths'>;
  reviewedByUser?: { id: string; email: string } | null;
  appliedByUser?: { id: string; email: string } | null;
  reviewStatus: ReviewStatus;
}

/** Review queue summary */
export interface ReviewQueueSummary {
  totalPendingReview: number;
  byConfidenceLevel: Record<ConfidenceLevel, number>;
  byAssumptionType: Record<AssumptionType, number>;
  oldestPendingDate: Date | null;
}

/** Inference result for batch operations */
export interface InferenceResult {
  created: number;
  skipped: number;
  errors: Array<{ trainId: string; pmTypeId: string; error: string }>;
  assumptions: AssumptionWithDetails[];
}

// =============================================================================
// Service Implementation
// =============================================================================

/**
 * Baseline Assumption Service
 *
 * Manages PM history assumptions for cold start data migration scenarios.
 */
export class BaselineAssumptionService extends BaseService {
  constructor() {
    super({ name: 'baseline-assumption-service' });
  }

  // ===========================================================================
  // CRUD Operations
  // ===========================================================================

  /**
   * Create a new baseline assumption
   */
  async createAssumption(
    request: CreateAssumptionRequest,
    userId?: string
  ): Promise<AssumptionWithDetails> {
    return this.traced('createAssumption', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, request.trainId);

      // Validate train exists
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, request.trainId),
      });
      if (!train) {
        throw new NotFoundError('Train not found', {
          entityType: 'train',
          entityId: request.trainId,
        });
      }

      // Validate PM type exists
      const pmType = await this.db.query.pmTypes.findFirst({
        where: eq(pmTypes.id, request.pmTypeId),
      });
      if (!pmType) {
        throw new NotFoundError('PM type not found', {
          entityType: 'pmType',
          entityId: request.pmTypeId,
        });
      }

      // Check for existing assumption
      const existing = await this.db.query.pmBaselineAssumptions.findFirst({
        where: and(
          eq(pmBaselineAssumptions.trainId, request.trainId),
          eq(pmBaselineAssumptions.pmTypeId, request.pmTypeId)
        ),
      });
      if (existing) {
        throw new ConflictError(
          `Assumption already exists for train ${train.trainNumber} and PM type ${pmType.pmCode}`,
          { existingId: existing.id }
        );
      }

      // Determine if review is required based on confidence
      const requiresReview =
        request.requiresReview ??
        (request.confidenceLevel === 'LOW' || request.confidenceLevel === 'ESTIMATED');

      const newAssumption: NewPmBaselineAssumption = {
        trainId: request.trainId,
        pmTypeId: request.pmTypeId,
        assumptionType: request.assumptionType,
        assumedLastPmDate: request.assumedLastPmDate ?? null,
        assumedLastPmMileage: request.assumedLastPmMileage ?? null,
        confidenceLevel: request.confidenceLevel,
        inferenceSource: request.inferenceSource ?? null,
        inferenceData: request.inferenceData ?? null,
        requiresReview,
      };

      const [created] = await this.db
        .insert(pmBaselineAssumptions)
        .values(newAssumption)
        .returning();

      this.log.info(
        { assumptionId: created.id, trainId: request.trainId, pmTypeCode: pmType.pmCode },
        'Created baseline assumption'
      );

      return this.getAssumptionById(created.id);
    });
  }

  /**
   * Get assumption by ID with full details
   */
  async getAssumptionById(id: string): Promise<AssumptionWithDetails> {
    return this.traced('getAssumptionById', async (span) => {
      span.setAttribute('assumption.id', id);

      const assumption = await this.db.query.pmBaselineAssumptions.findFirst({
        where: eq(pmBaselineAssumptions.id, id),
        with: {
          train: true,
          pmType: true,
          reviewedByUser: true,
          appliedByUser: true,
        },
      });

      if (!assumption) {
        throw new NotFoundError('Assumption not found', {
          entityType: 'pmBaselineAssumption',
          entityId: id,
        });
      }

      return this.mapToAssumptionWithDetails(assumption);
    });
  }

  /**
   * List assumptions with filtering and pagination
   */
  async listAssumptions(
    filters: AssumptionFilters = {},
    pagination: PaginationOptions = {}
  ): Promise<PaginatedResult<AssumptionWithDetails>> {
    return this.traced('listAssumptions', async (span) => {
      const page = pagination.page ?? 1;
      const pageSize = pagination.pageSize ?? 20;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: SQL<unknown>[] = [];

      if (filters.trainId) {
        conditions.push(eq(pmBaselineAssumptions.trainId, filters.trainId));
      }
      if (filters.pmTypeId) {
        conditions.push(eq(pmBaselineAssumptions.pmTypeId, filters.pmTypeId));
      }
      if (filters.confidenceLevel) {
        const levels = Array.isArray(filters.confidenceLevel)
          ? filters.confidenceLevel
          : [filters.confidenceLevel];
        conditions.push(inArray(pmBaselineAssumptions.confidenceLevel, levels));
      }
      if (filters.assumptionType) {
        const types = Array.isArray(filters.assumptionType)
          ? filters.assumptionType
          : [filters.assumptionType];
        conditions.push(inArray(pmBaselineAssumptions.assumptionType, types));
      }
      if (filters.requiresReview !== undefined) {
        conditions.push(eq(pmBaselineAssumptions.requiresReview, filters.requiresReview));
      }
      if (filters.reviewed !== undefined) {
        if (filters.reviewed) {
          conditions.push(sql`${pmBaselineAssumptions.reviewedAt} IS NOT NULL`);
        } else {
          conditions.push(isNull(pmBaselineAssumptions.reviewedAt));
        }
      }
      if (filters.applied !== undefined) {
        if (filters.applied) {
          conditions.push(sql`${pmBaselineAssumptions.appliedAt} IS NOT NULL`);
        } else {
          conditions.push(isNull(pmBaselineAssumptions.appliedAt));
        }
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ total }] = await this.db
        .select({ total: count() })
        .from(pmBaselineAssumptions)
        .where(whereClause);

      // Build order by
      let orderBy: SQL;
      const sortOrder = pagination.sortOrder === 'asc' ? asc : desc;
      switch (pagination.sortBy) {
        case 'confidenceLevel':
          orderBy = sortOrder(pmBaselineAssumptions.confidenceLevel);
          break;
        case 'trainNumber':
          orderBy = sortOrder(trains.trainNumber);
          break;
        default:
          orderBy = sortOrder(pmBaselineAssumptions.createdAt);
      }

      // Query with joins
      const results = await this.db.query.pmBaselineAssumptions.findMany({
        where: whereClause,
        with: {
          train: true,
          pmType: true,
          reviewedByUser: true,
          appliedByUser: true,
        },
        orderBy: [orderBy],
        limit: pageSize,
        offset,
      });

      span.setAttribute('results.count', results.length);
      span.setAttribute('results.total', total);

      return {
        items: results.map((r) => this.mapToAssumptionWithDetails(r)),
        total,
        page,
        pageSize,
        totalPages: Math.ceil(total / pageSize),
      };
    });
  }

  /**
   * Update an assumption
   */
  async updateAssumption(
    id: string,
    request: UpdateAssumptionRequest,
    userId?: string
  ): Promise<AssumptionWithDetails> {
    return this.traced('updateAssumption', async (span) => {
      span.setAttribute('assumption.id', id);

      const existing = await this.db.query.pmBaselineAssumptions.findFirst({
        where: eq(pmBaselineAssumptions.id, id),
      });

      if (!existing) {
        throw new NotFoundError('Assumption not found', {
          entityType: 'pmBaselineAssumption',
          entityId: id,
        });
      }

      // Cannot update applied assumptions
      if (existing.appliedAt) {
        throw new ConflictError('Cannot update an assumption that has already been applied');
      }

      const updates: Partial<NewPmBaselineAssumption> = {
        updatedAt: new Date(),
      };

      if (request.assumedLastPmDate !== undefined) {
        updates.assumedLastPmDate = request.assumedLastPmDate;
      }
      if (request.assumedLastPmMileage !== undefined) {
        updates.assumedLastPmMileage = request.assumedLastPmMileage;
      }
      if (request.confidenceLevel !== undefined) {
        updates.confidenceLevel = request.confidenceLevel;
        // Update review requirement based on new confidence
        updates.requiresReview =
          request.confidenceLevel === 'LOW' || request.confidenceLevel === 'ESTIMATED';
      }
      if (request.inferenceSource !== undefined) {
        updates.inferenceSource = request.inferenceSource;
      }
      if (request.inferenceData !== undefined) {
        updates.inferenceData = request.inferenceData;
      }
      if (request.requiresReview !== undefined) {
        updates.requiresReview = request.requiresReview;
      }

      await this.db
        .update(pmBaselineAssumptions)
        .set(updates)
        .where(eq(pmBaselineAssumptions.id, id));

      this.log.info({ assumptionId: id }, 'Updated baseline assumption');

      return this.getAssumptionById(id);
    });
  }

  /**
   * Delete an assumption
   */
  async deleteAssumption(id: string): Promise<void> {
    return this.traced('deleteAssumption', async (span) => {
      span.setAttribute('assumption.id', id);

      const existing = await this.db.query.pmBaselineAssumptions.findFirst({
        where: eq(pmBaselineAssumptions.id, id),
      });

      if (!existing) {
        throw new NotFoundError('Assumption not found', {
          entityType: 'pmBaselineAssumption',
          entityId: id,
        });
      }

      // Cannot delete applied assumptions
      if (existing.appliedAt) {
        throw new ConflictError('Cannot delete an assumption that has already been applied');
      }

      await this.db.delete(pmBaselineAssumptions).where(eq(pmBaselineAssumptions.id, id));

      this.log.info({ assumptionId: id }, 'Deleted baseline assumption');
    });
  }

  // ===========================================================================
  // Review Queue Operations
  // ===========================================================================

  /**
   * Get assumptions requiring manual review (the review queue)
   */
  async getReviewQueue(pagination: PaginationOptions = {}): Promise<PaginatedResult<AssumptionWithDetails>> {
    return this.traced('getReviewQueue', async (span) => {
      return this.listAssumptions(
        {
          requiresReview: true,
          reviewed: false,
        },
        {
          ...pagination,
          sortBy: pagination.sortBy ?? 'createdAt',
          sortOrder: pagination.sortOrder ?? 'asc', // Oldest first
        }
      );
    });
  }

  /**
   * Get review queue summary statistics
   */
  async getReviewQueueSummary(): Promise<ReviewQueueSummary> {
    return this.traced('getReviewQueueSummary', async (span) => {
      // Get pending review assumptions
      const pendingReview = await this.db.query.pmBaselineAssumptions.findMany({
        where: and(
          eq(pmBaselineAssumptions.requiresReview, true),
          isNull(pmBaselineAssumptions.reviewedAt)
        ),
      });

      // Count by confidence level
      const byConfidenceLevel: Record<ConfidenceLevel, number> = {
        HIGH: 0,
        MEDIUM: 0,
        LOW: 0,
        ESTIMATED: 0,
      };

      // Count by assumption type
      const byAssumptionType: Record<AssumptionType, number> = {
        INFERRED_FROM_COMMISSIONING: 0,
        INFERRED_FROM_HIGHER_PM: 0,
        MANUAL_OVERRIDE: 0,
        IMPORTED: 0,
        NO_HISTORY: 0,
      };

      let oldestDate: Date | null = null;

      for (const assumption of pendingReview) {
        byConfidenceLevel[assumption.confidenceLevel as ConfidenceLevel]++;
        byAssumptionType[assumption.assumptionType as AssumptionType]++;

        if (!oldestDate || (assumption.createdAt && assumption.createdAt < oldestDate)) {
          oldestDate = assumption.createdAt;
        }
      }

      return {
        totalPendingReview: pendingReview.length,
        byConfidenceLevel,
        byAssumptionType,
        oldestPendingDate: oldestDate,
      };
    });
  }

  /**
   * Review an assumption (approve or reject)
   */
  async reviewAssumption(
    id: string,
    request: ReviewAssumptionRequest,
    userId: string
  ): Promise<AssumptionWithDetails> {
    return this.traced('reviewAssumption', async (span) => {
      span.setAttribute('assumption.id', id);
      span.setAttribute('review.approved', request.approved);

      const existing = await this.db.query.pmBaselineAssumptions.findFirst({
        where: eq(pmBaselineAssumptions.id, id),
      });

      if (!existing) {
        throw new NotFoundError('Assumption not found', {
          entityType: 'pmBaselineAssumption',
          entityId: id,
        });
      }

      // Already applied cannot be reviewed again
      if (existing.appliedAt) {
        throw new ConflictError('Cannot review an assumption that has already been applied');
      }

      const updates: Partial<NewPmBaselineAssumption> = {
        reviewedBy: userId,
        reviewedAt: new Date(),
        reviewNotes: request.reviewNotes ?? null,
        updatedAt: new Date(),
      };

      if (request.approved) {
        // If corrections provided, update the assumed values
        if (request.correctedDate !== undefined) {
          updates.assumedLastPmDate = request.correctedDate;
        }
        if (request.correctedMileage !== undefined) {
          updates.assumedLastPmMileage = request.correctedMileage;
        }
        // Upgrade confidence if corrections were made
        if (request.correctedDate !== undefined || request.correctedMileage !== undefined) {
          updates.confidenceLevel = 'HIGH';
          updates.assumptionType = 'MANUAL_OVERRIDE';
        }
        // Clear the review flag
        updates.requiresReview = false;
      } else {
        // Rejected - keep in review queue or mark for deletion
        updates.reviewNotes = `REJECTED: ${request.reviewNotes ?? 'No reason provided'}`;
      }

      await this.db
        .update(pmBaselineAssumptions)
        .set(updates)
        .where(eq(pmBaselineAssumptions.id, id));

      this.log.info(
        { assumptionId: id, approved: request.approved, reviewedBy: userId },
        `Assumption ${request.approved ? 'approved' : 'rejected'}`
      );

      return this.getAssumptionById(id);
    });
  }

  /**
   * Apply an assumption to the PM scheduling baseline
   *
   * This marks the assumption as applied and updates PM scheduler calculations.
   */
  async applyAssumption(
    id: string,
    request: ApplyAssumptionRequest,
    userId: string
  ): Promise<AssumptionWithDetails> {
    return this.traced('applyAssumption', async (span) => {
      span.setAttribute('assumption.id', id);

      const existing = await this.db.query.pmBaselineAssumptions.findFirst({
        where: eq(pmBaselineAssumptions.id, id),
        with: {
          train: true,
          pmType: true,
        },
      });

      if (!existing) {
        throw new NotFoundError('Assumption not found', {
          entityType: 'pmBaselineAssumption',
          entityId: id,
        });
      }

      // Must be reviewed first (unless HIGH confidence)
      if (
        existing.requiresReview &&
        !existing.reviewedAt &&
        existing.confidenceLevel !== 'HIGH'
      ) {
        throw new ValidationError(
          'Assumption must be reviewed before it can be applied',
          { field: 'reviewedAt' }
        );
      }

      // Already applied
      if (existing.appliedAt) {
        throw new ConflictError('Assumption has already been applied');
      }

      // Determine final values
      const finalDate = request.overrideDate ?? existing.assumedLastPmDate;
      const finalMileage = request.overrideMileage ?? existing.assumedLastPmMileage;

      if (!finalDate && !finalMileage) {
        throw new ValidationError(
          'Cannot apply assumption without a date or mileage value',
          { field: 'assumedLastPmDate' }
        );
      }

      // Update the assumption as applied
      await this.db
        .update(pmBaselineAssumptions)
        .set({
          appliedAt: new Date(),
          appliedBy: userId,
          assumedLastPmDate: finalDate,
          assumedLastPmMileage: finalMileage,
          updatedAt: new Date(),
        })
        .where(eq(pmBaselineAssumptions.id, id));

      this.log.info(
        {
          assumptionId: id,
          trainId: existing.trainId,
          pmTypeId: existing.pmTypeId,
          appliedDate: finalDate,
          appliedMileage: finalMileage,
          appliedBy: userId,
        },
        'Applied baseline assumption'
      );

      return this.getAssumptionById(id);
    });
  }

  // ===========================================================================
  // Inference Operations
  // ===========================================================================

  /**
   * Infer assumptions from train commissioning date
   *
   * For each PM type, assumes the first PM occurred at commissioning date + interval.
   * Sets confidence to LOW and requires review.
   */
  async inferFromCommissioning(
    request: InferFromCommissioningRequest,
    userId?: string
  ): Promise<InferenceResult> {
    return this.traced('inferFromCommissioning', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, request.trainId);

      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, request.trainId),
      });

      if (!train) {
        throw new NotFoundError('Train not found', {
          entityType: 'train',
          entityId: request.trainId,
        });
      }

      if (!train.commissioningDate) {
        throw new ValidationError(
          'Train does not have a commissioning date set',
          { field: 'commissioningDate' }
        );
      }

      // Get PM types for this train's fleet
      let pmTypesQuery = this.db.query.pmTypes.findMany({
        where: train.fleetId ? eq(pmTypes.fleetId, train.fleetId) : undefined,
      });

      const fleetPmTypes = await pmTypesQuery;

      // Filter by requested codes if provided
      const targetPmTypes = request.pmTypeCodes
        ? fleetPmTypes.filter((pt) => request.pmTypeCodes!.includes(pt.pmCode))
        : fleetPmTypes;

      const result: InferenceResult = {
        created: 0,
        skipped: 0,
        errors: [],
        assumptions: [],
      };

      const commissioningDate = new Date(train.commissioningDate);

      for (const pmType of targetPmTypes) {
        try {
          // Check if assumption already exists
          const existing = await this.db.query.pmBaselineAssumptions.findFirst({
            where: and(
              eq(pmBaselineAssumptions.trainId, train.id),
              eq(pmBaselineAssumptions.pmTypeId, pmType.id)
            ),
          });

          if (existing) {
            result.skipped++;
            continue;
          }

          // Calculate assumed first PM date
          const intervalMonths =
            pmType.intervalMonths ?? DEFAULT_PM_INTERVALS[pmType.pmCode] ?? 12;
          const assumedFirstPmDate = addMonths(commissioningDate, intervalMonths);

          // Calculate assumed mileage if interval is known
          let assumedMileage: number | undefined;
          if (pmType.intervalKm && train.currentMileageKm) {
            // Rough estimate based on interval
            assumedMileage = pmType.intervalKm;
          }

          const assumption = await this.createAssumption(
            {
              trainId: train.id,
              pmTypeId: pmType.id,
              assumptionType: 'INFERRED_FROM_COMMISSIONING',
              assumedLastPmDate: format(assumedFirstPmDate, 'yyyy-MM-dd'),
              assumedLastPmMileage: assumedMileage,
              confidenceLevel: 'LOW',
              inferenceSource: `Inferred from commissioning date ${train.commissioningDate}`,
              inferenceData: {
                commissioningDate: train.commissioningDate,
                intervalMonths,
                calculationMethod: 'commission_date_plus_interval',
              },
              requiresReview: true,
            },
            userId
          );

          result.created++;
          result.assumptions.push(assumption);
        } catch (error) {
          result.errors.push({
            trainId: train.id,
            pmTypeId: pmType.id,
            error: error instanceof Error ? error.message : String(error),
          });
        }
      }

      this.log.info(
        {
          trainId: train.id,
          created: result.created,
          skipped: result.skipped,
          errors: result.errors.length,
        },
        'Completed commissioning date inference'
      );

      return result;
    });
  }

  /**
   * Infer assumptions from a known higher-level PM
   *
   * When a higher PM (like C4) is known, it satisfies and resets counters
   * for lower PMs (C1, C2, C3).
   */
  async inferFromHigherPm(
    request: InferFromHigherPmRequest,
    userId?: string
  ): Promise<InferenceResult> {
    return this.traced('inferFromHigherPm', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, request.trainId);

      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, request.trainId),
      });

      if (!train) {
        throw new NotFoundError('Train not found', {
          entityType: 'train',
          entityId: request.trainId,
        });
      }

      // Find the known PM type
      const knownPmType = await this.db.query.pmTypes.findFirst({
        where: and(
          eq(pmTypes.pmCode, request.knownPmTypeCode),
          train.fleetId ? eq(pmTypes.fleetId, train.fleetId) : undefined
        ),
      });

      if (!knownPmType) {
        throw new NotFoundError('PM type not found', {
          entityType: 'pmType',
          entityId: request.knownPmTypeCode,
        });
      }

      // Get satisfied PM codes from hierarchy
      const satisfiedCodes = PM_HIERARCHY[request.knownPmTypeCode] ?? [];

      if (satisfiedCodes.length === 0) {
        return {
          created: 0,
          skipped: 0,
          errors: [],
          assumptions: [],
        };
      }

      // Get PM types for satisfied codes
      const satisfiedPmTypes = await this.db.query.pmTypes.findMany({
        where: and(
          inArray(pmTypes.pmCode, satisfiedCodes),
          train.fleetId ? eq(pmTypes.fleetId, train.fleetId) : undefined
        ),
      });

      const result: InferenceResult = {
        created: 0,
        skipped: 0,
        errors: [],
        assumptions: [],
      };

      for (const pmType of satisfiedPmTypes) {
        try {
          // Check if assumption already exists
          const existing = await this.db.query.pmBaselineAssumptions.findFirst({
            where: and(
              eq(pmBaselineAssumptions.trainId, train.id),
              eq(pmBaselineAssumptions.pmTypeId, pmType.id)
            ),
          });

          if (existing) {
            result.skipped++;
            continue;
          }

          const assumption = await this.createAssumption(
            {
              trainId: train.id,
              pmTypeId: pmType.id,
              assumptionType: 'INFERRED_FROM_HIGHER_PM',
              assumedLastPmDate: request.knownPmDate,
              assumedLastPmMileage: request.knownPmMileage,
              confidenceLevel: 'HIGH', // High confidence because derived from actual PM
              inferenceSource: `Counters reset by ${request.knownPmTypeCode} on ${request.knownPmDate}`,
              inferenceData: {
                higherPmCode: request.knownPmTypeCode,
                higherPmDate: request.knownPmDate,
                higherPmMileage: request.knownPmMileage,
                satisfiedBy: request.knownPmTypeCode,
              },
              requiresReview: false, // High confidence, no review needed
            },
            userId
          );

          result.created++;
          result.assumptions.push(assumption);
        } catch (error) {
          result.errors.push({
            trainId: train.id,
            pmTypeId: pmType.id,
            error: error instanceof Error ? error.message : String(error),
          });
        }
      }

      // Also create/update assumption for the known PM itself
      try {
        const existingKnown = await this.db.query.pmBaselineAssumptions.findFirst({
          where: and(
            eq(pmBaselineAssumptions.trainId, train.id),
            eq(pmBaselineAssumptions.pmTypeId, knownPmType.id)
          ),
        });

        if (!existingKnown) {
          const assumption = await this.createAssumption(
            {
              trainId: train.id,
              pmTypeId: knownPmType.id,
              assumptionType: 'IMPORTED',
              assumedLastPmDate: request.knownPmDate,
              assumedLastPmMileage: request.knownPmMileage,
              confidenceLevel: 'HIGH',
              inferenceSource: 'Imported known PM completion',
              inferenceData: {
                source: 'inferFromHigherPm',
              },
              requiresReview: false,
            },
            userId
          );
          result.created++;
          result.assumptions.push(assumption);
        }
      } catch (error) {
        result.errors.push({
          trainId: train.id,
          pmTypeId: knownPmType.id,
          error: error instanceof Error ? error.message : String(error),
        });
      }

      this.log.info(
        {
          trainId: train.id,
          knownPmCode: request.knownPmTypeCode,
          created: result.created,
          skipped: result.skipped,
          errors: result.errors.length,
        },
        'Completed higher PM inference'
      );

      return result;
    });
  }

  /**
   * Get assumptions for a train (useful for PM scheduler integration)
   */
  async getAssumptionsForTrain(trainId: string): Promise<AssumptionWithDetails[]> {
    return this.traced('getAssumptionsForTrain', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      const result = await this.listAssumptions({ trainId }, { pageSize: 100 });
      return result.items;
    });
  }

  /**
   * Get applied assumptions for PM baseline calculation
   */
  async getAppliedAssumptions(trainId?: string): Promise<AssumptionWithDetails[]> {
    return this.traced('getAppliedAssumptions', async (span) => {
      if (trainId) {
        span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      }

      const result = await this.listAssumptions(
        {
          trainId,
          applied: true,
        },
        { pageSize: 1000 }
      );

      return result.items;
    });
  }

  // ===========================================================================
  // Private Helpers
  // ===========================================================================

  /**
   * Map database result to AssumptionWithDetails
   */
  private mapToAssumptionWithDetails(
    assumption: PmBaselineAssumption & {
      train?: Train | null;
      pmType?: PmType | null;
      reviewedByUser?: { id: string; email: string } | null;
      appliedByUser?: { id: string; email: string } | null;
    }
  ): AssumptionWithDetails {
    // Determine review status
    let reviewStatus: ReviewStatus;
    if (assumption.appliedAt) {
      reviewStatus = 'APPLIED';
    } else if (assumption.reviewedAt) {
      if (assumption.reviewNotes?.startsWith('REJECTED:')) {
        reviewStatus = 'REJECTED';
      } else {
        reviewStatus = 'REVIEWED';
      }
    } else {
      reviewStatus = 'PENDING_REVIEW';
    }

    return {
      ...assumption,
      train: assumption.train
        ? {
            id: assumption.train.id,
            trainNumber: assumption.train.trainNumber,
            currentMileageKm: assumption.train.currentMileageKm,
            commissioningDate: assumption.train.commissioningDate,
          }
        : ({
            id: assumption.trainId,
            trainNumber: 'Unknown',
            currentMileageKm: 0,
            commissioningDate: null,
          } as Pick<Train, 'id' | 'trainNumber' | 'currentMileageKm' | 'commissioningDate'>),
      pmType: assumption.pmType
        ? {
            id: assumption.pmType.id,
            pmCode: assumption.pmType.pmCode,
            intervalKm: assumption.pmType.intervalKm,
            intervalMonths: assumption.pmType.intervalMonths,
          }
        : ({
            id: assumption.pmTypeId,
            pmCode: 'Unknown',
            intervalKm: null,
            intervalMonths: null,
          } as Pick<PmType, 'id' | 'pmCode' | 'intervalKm' | 'intervalMonths'>),
      reviewedByUser: assumption.reviewedByUser ?? null,
      appliedByUser: assumption.appliedByUser ?? null,
      reviewStatus,
    };
  }
}

// =============================================================================
// Singleton Instance
// =============================================================================

let baselineAssumptionServiceInstance: BaselineAssumptionService | null = null;

/**
 * Get singleton instance of BaselineAssumptionService
 */
export function getBaselineAssumptionService(): BaselineAssumptionService {
  if (!baselineAssumptionServiceInstance) {
    baselineAssumptionServiceInstance = new BaselineAssumptionService();
  }
  return baselineAssumptionServiceInstance;
}

