/**
 * MMS Costing Service
 *
 * Calculates TCO (Total Cost of Ownership) projections, tracks variance against budget,
 * and provides cost impact analysis for schedule adjustments.
 *
 * Key responsibilities:
 * - Calculate individual PM costs (labor + materials + overhead)
 * - Project 12-year TCO with inflation and NPV calculations
 * - Track budget vs. actual cost variance
 * - Support depot-level and global cost analysis
 *
 * Cost calculation components:
 * - Labor: Hours × shop rate with shift multipliers
 * - Materials: Part costs from PM material requirements
 * - Overhead: 18% of direct costs (industry standard)
 *
 * Financial parameters (12-year contract):
 * - Inflation: 3% annually
 * - Discount rate: 5% for NPV calculations
 * - Variance tolerance: 10% before flagging as over-budget
 *
 * @see specs/004-domain-services.md Section 4.10
 */

import { eq, and, gte, lte, isNull, sql, desc } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  pmSchedule,
  pmTypes,
  pmMaterialRequirements,
  laborRates,
  materialCosts,
  costBaselines,
} from '../lib/db/schema';
import { NotFoundError } from '../lib/errors';
import { costingMetrics } from '../lib/metrics';

/** PM schedule record type (inferred from schema) */
type PmScheduleRecord = typeof pmSchedule.$inferSelect;

/** PM type record (inferred from schema) */
type PmTypeRecord = typeof pmTypes.$inferSelect;

// =============================================================================
// Constants
// =============================================================================

/** Overhead rate applied to direct costs (labor + materials) */
export const OVERHEAD_RATE = 0.18;

/** Annual inflation rate for TCO projections */
export const INFLATION_RATE = 0.03;

/** Discount rate for NPV calculations */
export const DISCOUNT_RATE = 0.05;

/** Default TCO projection horizon in years (contract period) */
export const DEFAULT_HORIZON_YEARS = 12;

/** Budget variance tolerance before flagging as over-budget */
export const VARIANCE_TOLERANCE = 0.10;

/** Overtime multiplier for night shift (default if not in labor rates) */
export const DEFAULT_OVERTIME_MULTIPLIER = 1.35;

/** Weekend multiplier (default if not in labor rates) */
export const DEFAULT_WEEKEND_MULTIPLIER = 1.5;

/** Default shop rate if not configured (SGD/hour) */
export const DEFAULT_SHOP_RATE = 85.0;

// =============================================================================
// Types
// =============================================================================

/** Detailed cost breakdown for a PM */
export interface CostBreakdown {
  laborCost: number;
  overtimeCost: number;
  materialCost: number;
  contractorCost: number;
  overheadCost: number;
  totalCost: number;
}

/** Yearly cost projection for TCO */
export interface YearlyCost {
  fiscalYear: number;
  laborCost: number;
  materialCost: number;
  totalCost: number;
  pmCount: number;
  inflationFactor: number;
}

/** TCO projection summary */
export interface TCOSummary {
  totalLaborCost: number;
  totalMaterialCost: number;
  totalCost: number;
  totalPMCount: number;
  npv: number;
  avgAnnualCost: number;
}

/** Full TCO projection result */
export interface TCOProjection {
  projections: YearlyCost[];
  summary: TCOSummary;
  horizonYears: number;
  calculatedAt: Date;
}

/** Budget figures for variance calculation */
export interface BudgetFigures {
  labor: number;
  material: number;
  total: number;
}

/** Actual cost figures for variance calculation */
export interface ActualFigures {
  labor: number;
  material: number;
  total: number;
}

/** Variance figures */
export interface VarianceFigures {
  labor: number;
  material: number;
  total: number;
  percentage: number;
}

/** Variance status */
export type VarianceStatus = 'UNDER_BUDGET' | 'WITHIN_TOLERANCE' | 'OVER_BUDGET';

/** Cost variance analysis result */
export interface CostVariance {
  fiscalYear: number;
  depotId: string | null;
  depotCode?: string;
  budget: BudgetFigures;
  actual: ActualFigures;
  variance: VarianceFigures;
  status: VarianceStatus;
  pmCompleted: number;
  calculatedAt: Date;
}

/** Labor rate lookup result */
export interface LaborRate {
  id: string;
  depotId: string | null;
  regularHourlyRate: number;
  overtimeMultiplier: number;
  weekendMultiplier: number;
  holidayMultiplier: number;
  shopRateHourly: number;
  currency: string;
  effectiveFrom: Date;
  effectiveTo: Date | null;
}

/** PM cost calculation request */
export interface CalculatePMCostRequest {
  pmScheduleId: string;
  includeProjected?: boolean;
}

/** TCO projection request */
export interface ProjectTCORequest {
  horizonYears?: number;
  scenarioId?: string;
  depotId?: string;
}

/** Cost variance request */
export interface CalculateVarianceRequest {
  fiscalYear: number;
  depotId?: string;
}

// =============================================================================
// Singleton Instance
// =============================================================================

let instance: CostingService | null = null;

/**
 * Get the singleton CostingService instance
 */
export function getCostingService(): CostingService {
  if (!instance) {
    instance = new CostingService();
  }
  return instance;
}

// =============================================================================
// CostingService Implementation
// =============================================================================

/**
 * Costing Service for TCO projections and cost analysis
 *
 * @example
 * ```typescript
 * const costingService = getCostingService();
 *
 * // Calculate cost for a single PM
 * const cost = await costingService.calculatePMCost({
 *   pmScheduleId: 'pm-123'
 * });
 *
 * // Project 12-year TCO
 * const tco = await costingService.projectTCO();
 *
 * // Calculate variance for current fiscal year
 * const variance = await costingService.calculateVariance({
 *   fiscalYear: 2026,
 *   depotId: 'depot-001'
 * });
 * ```
 */
export class CostingService extends BaseService {
  constructor() {
    super({ name: 'costing-service' });
  }

  // ===========================================================================
  // Public Methods
  // ===========================================================================

  /**
   * Calculate the cost breakdown for a specific PM
   *
   * Includes labor (with overtime multipliers), materials, and overhead.
   *
   * @param request - PM cost calculation request
   * @returns Detailed cost breakdown
   * @throws NotFoundError if PM not found
   */
  async calculatePMCost(request: CalculatePMCostRequest): Promise<CostBreakdown> {
    return this.traced('calculatePMCost', async (span) => {
      span.setAttribute(MmsAttributes.PM_SCHEDULE_ID, request.pmScheduleId);

      // Fetch PM with relations
      const pm = await this.db.query.pmSchedule.findFirst({
        where: eq(pmSchedule.id, request.pmScheduleId),
        with: {
          pmType: true,
          assignedDepot: true,
        },
      });

      if (!pm) {
        throw new NotFoundError('PM schedule not found', {
          entityType: 'PM_SCHEDULE',
          entityId: request.pmScheduleId,
        });
      }

      span.setAttribute(MmsAttributes.TRAIN_ID, pm.trainId);
      span.setAttribute(MmsAttributes.PM_TYPE_CODE, pm.pmType?.pmCode || 'UNKNOWN');

      // Get labor rate for depot and date
      const laborRate = await this.getLaborRate(
        pm.assignedDepotId || null,
        pm.targetDate ? new Date(pm.targetDate) : new Date()
      );

      // Calculate material cost
      const materialCost = await this.calculateMaterialCost(pm.pmTypeId);

      // Determine hours: actual > assigned > estimated
      const hours = this.resolveHours(pm, pm.pmType);

      // Calculate labor cost using shop rate
      const shopRate = laborRate?.shopRateHourly || DEFAULT_SHOP_RATE;
      const laborCost = hours * shopRate;

      // Calculate overtime cost if night/weekend shift
      let overtimeCost = 0;
      if (pm.assignedShift && laborRate) {
        overtimeCost = this.calculateOvertimeCost(
          hours,
          laborRate.regularHourlyRate,
          pm.assignedShift,
          laborRate
        );
      }

      // Overhead: 18% of direct costs
      const directCost = laborCost + materialCost;
      const overheadCost = directCost * OVERHEAD_RATE;

      const totalCost = laborCost + overtimeCost + materialCost + overheadCost;

      // Record metrics
      costingMetrics.pmCostCalculated.inc({
        pm_type: pm.pmType?.pmCode || 'UNKNOWN',
        depot_id: pm.assignedDepotId || 'UNASSIGNED',
      });

      this.log.info({
        pmScheduleId: request.pmScheduleId,
        hours,
        laborCost,
        overtimeCost,
        materialCost,
        overheadCost,
        totalCost,
      }, 'PM cost calculated');

      return {
        laborCost,
        overtimeCost,
        materialCost,
        contractorCost: 0, // Not yet implemented - placeholder for contractor work
        overheadCost,
        totalCost,
      };
    });
  }

  /**
   * Project Total Cost of Ownership over the contract horizon
   *
   * Calculates yearly costs with inflation adjustment and NPV.
   *
   * @param request - TCO projection request
   * @returns TCO projection with yearly breakdown and summary
   */
  async projectTCO(request: ProjectTCORequest = {}): Promise<TCOProjection> {
    return this.traced('projectTCO', async (span) => {
      const horizonYears = request.horizonYears || DEFAULT_HORIZON_YEARS;
      span.setAttribute('tco.horizon_years', horizonYears);

      if (request.scenarioId) {
        span.setAttribute('scenario.id', request.scenarioId);
      }
      if (request.depotId) {
        span.setAttribute(MmsAttributes.DEPOT_ID, request.depotId);
      }

      const projections: YearlyCost[] = [];
      const startYear = new Date().getFullYear();

      for (let yearOffset = 0; yearOffset < horizonYears; yearOffset++) {
        const fiscalYear = startYear + yearOffset;
        const yearStart = new Date(fiscalYear, 0, 1);
        const yearEnd = new Date(fiscalYear, 11, 31);

        // Build where conditions for PM query
        const whereConditions = [
          request.scenarioId
            ? eq(pmSchedule.scenarioId, request.scenarioId)
            : isNull(pmSchedule.scenarioId),
          gte(pmSchedule.targetDate, yearStart.toISOString().split('T')[0]),
          lte(pmSchedule.targetDate, yearEnd.toISOString().split('T')[0]),
        ];

        if (request.depotId) {
          whereConditions.push(eq(pmSchedule.assignedDepotId, request.depotId));
        }

        // Fetch scheduled PMs for this year
        const scheduledPMs = await this.db.query.pmSchedule.findMany({
          where: and(...whereConditions),
          with: { pmType: true },
        });

        // Calculate costs for each PM
        let totalLabor = 0;
        let totalMaterial = 0;

        for (const pm of scheduledPMs) {
          try {
            const cost = await this.calculatePMCost({
              pmScheduleId: pm.id,
              includeProjected: request.scenarioId ? true : false,
            });
            totalLabor += cost.laborCost + cost.overtimeCost;
            totalMaterial += cost.materialCost;
          } catch (error) {
            // Log but continue - don't fail entire projection for one PM
            this.log.warn({ pmId: pm.id, error }, 'Failed to calculate PM cost, using estimate');
            // Use estimated values based on PM type
            if (pm.pmType) {
              const hours = parseFloat(pm.pmType.estimatedHours || '0');
              totalLabor += hours * DEFAULT_SHOP_RATE;
            }
          }
        }

        // Apply inflation adjustment for future years
        const inflationFactor = Math.pow(1 + INFLATION_RATE, yearOffset);
        const adjustedLabor = totalLabor * inflationFactor;
        const adjustedMaterial = totalMaterial * inflationFactor;

        projections.push({
          fiscalYear,
          laborCost: adjustedLabor,
          materialCost: adjustedMaterial,
          totalCost: adjustedLabor + adjustedMaterial,
          pmCount: scheduledPMs.length,
          inflationFactor,
        });

        this.log.debug({
          fiscalYear,
          pmCount: scheduledPMs.length,
          laborCost: adjustedLabor,
          materialCost: adjustedMaterial,
        }, 'Year projection calculated');
      }

      // Calculate NPV - discount future costs to present value
      let npv = 0;
      for (let i = 0; i < projections.length; i++) {
        const yearCost = projections[i].totalCost;
        npv += yearCost / Math.pow(1 + DISCOUNT_RATE, i);
      }

      // Calculate summary
      const summary: TCOSummary = {
        totalLaborCost: projections.reduce((sum, p) => sum + p.laborCost, 0),
        totalMaterialCost: projections.reduce((sum, p) => sum + p.materialCost, 0),
        totalCost: projections.reduce((sum, p) => sum + p.totalCost, 0),
        totalPMCount: projections.reduce((sum, p) => sum + p.pmCount, 0),
        npv,
        avgAnnualCost: npv / horizonYears,
      };

      // Record metrics
      costingMetrics.tcoProjected.observe(summary.npv);

      this.log.info({
        horizonYears,
        totalCost: summary.totalCost,
        npv: summary.npv,
        totalPMCount: summary.totalPMCount,
      }, 'TCO projection complete');

      return {
        projections,
        summary,
        horizonYears,
        calculatedAt: new Date(),
      };
    });
  }

  /**
   * Calculate cost variance against budget for a fiscal year
   *
   * Compares actual costs from completed PMs against budget baseline.
   *
   * @param request - Variance calculation request
   * @returns Cost variance analysis
   * @throws NotFoundError if budget baseline not found
   */
  async calculateVariance(request: CalculateVarianceRequest): Promise<CostVariance> {
    return this.traced('calculateVariance', async (span) => {
      span.setAttribute('variance.fiscal_year', request.fiscalYear);
      if (request.depotId) {
        span.setAttribute(MmsAttributes.DEPOT_ID, request.depotId);
      }

      // Fetch cost baseline for the fiscal year
      const baseline = await this.db.query.costBaselines.findFirst({
        where: and(
          eq(costBaselines.fiscalYear, request.fiscalYear),
          request.depotId
            ? eq(costBaselines.depotId, request.depotId)
            : isNull(costBaselines.depotId)
        ),
        with: {
          depot: true,
        },
      });

      if (!baseline) {
        throw new NotFoundError(
          `Cost baseline not found for fiscal year ${request.fiscalYear}`,
          {
            entityType: 'COST_BASELINE',
            entityId: `${request.fiscalYear}-${request.depotId || 'GLOBAL'}`,
          }
        );
      }

      // Get actual costs from completed PMs in this fiscal year
      const yearStart = new Date(request.fiscalYear, 0, 1);
      const yearEnd = new Date(request.fiscalYear, 11, 31);

      const whereConditions = [
        eq(pmSchedule.status, 'COMPLETED'),
        gte(pmSchedule.completedAt, yearStart),
        lte(pmSchedule.completedAt, yearEnd),
        isNull(pmSchedule.scenarioId), // Only production PMs
      ];

      if (request.depotId) {
        whereConditions.push(eq(pmSchedule.assignedDepotId, request.depotId));
      }

      const completedPMs = await this.db.query.pmSchedule.findMany({
        where: and(...whereConditions),
        with: { pmType: true },
      });

      // Calculate actual costs
      let actualLaborCost = 0;
      let actualMaterialCost = 0;

      for (const pm of completedPMs) {
        try {
          const cost = await this.calculatePMCost({ pmScheduleId: pm.id });
          actualLaborCost += cost.laborCost + cost.overtimeCost;
          actualMaterialCost += cost.materialCost;
        } catch (error) {
          this.log.warn({ pmId: pm.id, error }, 'Failed to calculate completed PM cost');
        }
      }

      const actualTotal = actualLaborCost + actualMaterialCost;
      const budgetTotal = parseFloat(baseline.budgetTotal || '0');
      const budgetLabor = parseFloat(baseline.budgetLaborCost || '0');
      const budgetMaterial = parseFloat(baseline.budgetMaterialCost || '0');

      // Calculate variance
      const varianceLabor = actualLaborCost - budgetLabor;
      const varianceMaterial = actualMaterialCost - budgetMaterial;
      const varianceTotal = actualTotal - budgetTotal;
      const variancePercentage = budgetTotal > 0
        ? ((actualTotal - budgetTotal) / budgetTotal) * 100
        : 0;

      // Determine status
      let status: VarianceStatus;
      if (actualTotal <= budgetTotal) {
        status = 'UNDER_BUDGET';
      } else if (actualTotal <= budgetTotal * (1 + VARIANCE_TOLERANCE)) {
        status = 'WITHIN_TOLERANCE';
      } else {
        status = 'OVER_BUDGET';
      }

      // Record metrics
      costingMetrics.varianceCalculated.observe({
        fiscal_year: request.fiscalYear.toString(),
        depot_id: request.depotId || 'GLOBAL',
        status,
      }, variancePercentage);

      this.log.info({
        fiscalYear: request.fiscalYear,
        depotId: request.depotId,
        budgetTotal,
        actualTotal,
        variancePercentage,
        status,
        pmCompleted: completedPMs.length,
      }, 'Variance calculated');

      return {
        fiscalYear: request.fiscalYear,
        depotId: request.depotId || null,
        depotCode: (baseline as { depot?: { code?: string } }).depot?.code,
        budget: {
          labor: budgetLabor,
          material: budgetMaterial,
          total: budgetTotal,
        },
        actual: {
          labor: actualLaborCost,
          material: actualMaterialCost,
          total: actualTotal,
        },
        variance: {
          labor: varianceLabor,
          material: varianceMaterial,
          total: varianceTotal,
          percentage: variancePercentage,
        },
        status,
        pmCompleted: completedPMs.length,
        calculatedAt: new Date(),
      };
    });
  }

  // ===========================================================================
  // Labor Rate Methods
  // ===========================================================================

  /**
   * Get labor rate for a depot at a specific date
   *
   * Falls back to global rate if depot-specific rate not found.
   *
   * @param depotId - Depot ID (null for global)
   * @param date - Date for rate lookup
   * @returns Labor rate or null if not found
   */
  async getLaborRate(depotId: string | null, date: Date): Promise<LaborRate | null> {
    return this.traced('getLaborRate', async (span) => {
      if (depotId) {
        span.setAttribute(MmsAttributes.DEPOT_ID, depotId);
      }

      const dateStr = date.toISOString().split('T')[0];

      // Try depot-specific rate first
      if (depotId) {
        const depotRate = await this.db.query.laborRates.findFirst({
          where: and(
            eq(laborRates.depotId, depotId),
            lte(laborRates.effectiveFrom, dateStr),
            sql`(${laborRates.effectiveTo} IS NULL OR ${laborRates.effectiveTo} >= ${dateStr})`
          ),
          orderBy: [desc(laborRates.effectiveFrom)],
        });

        if (depotRate) {
          return this.mapLaborRate(depotRate);
        }
      }

      // Fall back to global rate
      const globalRate = await this.db.query.laborRates.findFirst({
        where: and(
          isNull(laborRates.depotId),
          lte(laborRates.effectiveFrom, dateStr),
          sql`(${laborRates.effectiveTo} IS NULL OR ${laborRates.effectiveTo} >= ${dateStr})`
        ),
        orderBy: [desc(laborRates.effectiveFrom)],
      });

      if (globalRate) {
        return this.mapLaborRate(globalRate);
      }

      this.log.warn({ depotId, date: dateStr }, 'No labor rate found, using defaults');
      return null;
    });
  }

  /**
   * Create or update a labor rate
   */
  async upsertLaborRate(rate: Omit<LaborRate, 'id'>): Promise<LaborRate> {
    return this.traced('upsertLaborRate', async (span) => {
      if (rate.depotId) {
        span.setAttribute(MmsAttributes.DEPOT_ID, rate.depotId);
      }

      const existing = await this.db.query.laborRates.findFirst({
        where: and(
          rate.depotId
            ? eq(laborRates.depotId, rate.depotId)
            : isNull(laborRates.depotId),
          eq(laborRates.effectiveFrom, rate.effectiveFrom.toISOString().split('T')[0])
        ),
      });

      if (existing) {
        const [updated] = await this.db
          .update(laborRates)
          .set({
            regularHourlyRate: rate.regularHourlyRate.toString(),
            overtimeMultiplier: rate.overtimeMultiplier.toString(),
            weekendMultiplier: rate.weekendMultiplier.toString(),
            holidayMultiplier: rate.holidayMultiplier.toString(),
            shopRateHourly: rate.shopRateHourly.toString(),
            effectiveTo: rate.effectiveTo?.toISOString().split('T')[0] || null,
          })
          .where(eq(laborRates.id, existing.id))
          .returning();

        return this.mapLaborRate(updated);
      }

      const [created] = await this.db
        .insert(laborRates)
        .values({
          depotId: rate.depotId,
          regularHourlyRate: rate.regularHourlyRate.toString(),
          overtimeMultiplier: rate.overtimeMultiplier.toString(),
          weekendMultiplier: rate.weekendMultiplier.toString(),
          holidayMultiplier: rate.holidayMultiplier.toString(),
          shopRateHourly: rate.shopRateHourly.toString(),
          effectiveFrom: rate.effectiveFrom.toISOString().split('T')[0],
          effectiveTo: rate.effectiveTo?.toISOString().split('T')[0] || null,
          currency: rate.currency,
        })
        .returning();

      return this.mapLaborRate(created);
    });
  }

  // ===========================================================================
  // Cost Baseline Methods
  // ===========================================================================

  /**
   * Create or update a cost baseline for a fiscal year
   */
  async upsertCostBaseline(baseline: {
    fiscalYear: number;
    depotId?: string | null;
    budgetLaborCost: number;
    budgetMaterialCost: number;
    budgetLaborHours?: number;
  }): Promise<typeof costBaselines.$inferSelect> {
    return this.traced('upsertCostBaseline', async (span) => {
      span.setAttribute('baseline.fiscal_year', baseline.fiscalYear);
      if (baseline.depotId) {
        span.setAttribute(MmsAttributes.DEPOT_ID, baseline.depotId);
      }

      const budgetTotal = baseline.budgetLaborCost + baseline.budgetMaterialCost;

      const existing = await this.db.query.costBaselines.findFirst({
        where: and(
          eq(costBaselines.fiscalYear, baseline.fiscalYear),
          baseline.depotId
            ? eq(costBaselines.depotId, baseline.depotId)
            : isNull(costBaselines.depotId)
        ),
      });

      if (existing) {
        const [updated] = await this.db
          .update(costBaselines)
          .set({
            budgetLaborCost: baseline.budgetLaborCost.toString(),
            budgetMaterialCost: baseline.budgetMaterialCost.toString(),
            budgetTotal: budgetTotal.toString(),
            budgetLaborHours: baseline.budgetLaborHours?.toString() || null,
            updatedAt: new Date(),
          })
          .where(eq(costBaselines.id, existing.id))
          .returning();

        return updated;
      }

      const [created] = await this.db
        .insert(costBaselines)
        .values({
          fiscalYear: baseline.fiscalYear,
          depotId: baseline.depotId || null,
          budgetLaborCost: baseline.budgetLaborCost.toString(),
          budgetMaterialCost: baseline.budgetMaterialCost.toString(),
          budgetTotal: budgetTotal.toString(),
          budgetLaborHours: baseline.budgetLaborHours?.toString() || null,
        })
        .returning();

      return created;
    });
  }

  /**
   * Get all cost baselines for a fiscal year
   */
  async getCostBaselines(fiscalYear: number): Promise<(typeof costBaselines.$inferSelect)[]> {
    return this.traced('getCostBaselines', async (span) => {
      span.setAttribute('baseline.fiscal_year', fiscalYear);

      return this.db.query.costBaselines.findMany({
        where: eq(costBaselines.fiscalYear, fiscalYear),
        with: { depot: true },
      });
    });
  }

  // ===========================================================================
  // Private Helpers
  // ===========================================================================

  /**
   * Calculate material cost for a PM type
   */
  private async calculateMaterialCost(pmTypeId: string): Promise<number> {
    // Get material requirements for this PM type
    const requirements = await this.db.query.pmMaterialRequirements.findMany({
      where: eq(pmMaterialRequirements.pmTypeId, pmTypeId),
    });

    let totalCost = 0;
    const today = new Date().toISOString().split('T')[0];

    for (const req of requirements) {
      // Get current material cost
      const cost = await this.db.query.materialCosts.findFirst({
        where: and(
          eq(materialCosts.partNumber, req.partNumber),
          lte(materialCosts.effectiveFrom, today),
          sql`(${materialCosts.effectiveTo} IS NULL OR ${materialCosts.effectiveTo} >= ${today})`
        ),
        orderBy: [desc(materialCosts.effectiveFrom)],
      });

      if (cost) {
        const unitCost = parseFloat(cost.unitCost || '0');
        const quantity = req.quantityPerPm || 1;
        totalCost += unitCost * quantity;
      } else {
        this.log.debug({ partNumber: req.partNumber }, 'No material cost found for part');
      }
    }

    return totalCost;
  }

  /**
   * Resolve hours for PM cost calculation
   * Priority: actual > assigned > estimated
   */
  private resolveHours(pm: PmScheduleRecord, pmType: PmTypeRecord | null): number {
    if (pm.actualHours) {
      return parseFloat(pm.actualHours);
    }
    if (pm.assignedHours) {
      return parseFloat(pm.assignedHours);
    }
    if (pmType?.estimatedHours) {
      return parseFloat(pmType.estimatedHours);
    }
    return 0;
  }

  /**
   * Calculate overtime cost based on shift type
   */
  private calculateOvertimeCost(
    hours: number,
    regularRate: number,
    shift: string,
    rate: LaborRate
  ): number {
    let multiplier = 1;

    switch (shift) {
      case 'NIGHT':
        multiplier = rate.overtimeMultiplier || DEFAULT_OVERTIME_MULTIPLIER;
        break;
      case 'WEEKEND':
        multiplier = rate.weekendMultiplier || DEFAULT_WEEKEND_MULTIPLIER;
        break;
      case 'HOLIDAY':
        multiplier = rate.holidayMultiplier || 2.5;
        break;
      default:
        return 0; // No overtime for regular shifts
    }

    // Overtime cost is the premium above regular rate
    return hours * regularRate * (multiplier - 1);
  }

  /**
   * Map database labor rate to LaborRate type
   */
  private mapLaborRate(rate: typeof laborRates.$inferSelect): LaborRate {
    return {
      id: rate.id,
      depotId: rate.depotId,
      regularHourlyRate: parseFloat(rate.regularHourlyRate || '0'),
      overtimeMultiplier: parseFloat(rate.overtimeMultiplier || '1.5'),
      weekendMultiplier: parseFloat(rate.weekendMultiplier || '2.0'),
      holidayMultiplier: parseFloat(rate.holidayMultiplier || '2.5'),
      shopRateHourly: parseFloat(rate.shopRateHourly || '0'),
      currency: rate.currency || 'SGD',
      effectiveFrom: new Date(rate.effectiveFrom),
      effectiveTo: rate.effectiveTo ? new Date(rate.effectiveTo) : null,
    };
  }
}

