/**
 * MMS Baseline Service
 *
 * Manages published plan baselines for drift analysis and scenario comparison.
 * Baselines are immutable snapshots of the PM schedule and mileage projections
 * at a point in time.
 *
 * Key responsibilities:
 * - Create and publish plan baselines
 * - Snapshot PM schedule and mileage projections
 * - Version management with semantic versioning
 * - Supersede previous baselines on new publication
 * - Audit logging for compliance
 *
 * Baseline lifecycle:
 * DRAFT -> PUBLISHED -> SUPERSEDED (when new baseline published)
 *
 * @see specs/004-domain-services.md Section 4.7
 */

import { eq, and, desc, sql, inArray, gte, count } from 'drizzle-orm';
import { addMonths, addYears, subDays, format } from 'date-fns';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  planBaselines,
  baselinePmSchedule,
  baselineMileageProjection,
  pmSchedule,
  trains,
  mileageReadings,
  auditLog,
  type PlanBaseline,
  type BaselinePmSchedule,
  type BaselineMileageProjection,
} from '../lib/db/schema';
import {
  NotFoundError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';

// =============================================================================
// Types
// =============================================================================

/** Status of a baseline in its lifecycle */
export type BaselineStatus = 'DRAFT' | 'PUBLISHED' | 'SUPERSEDED' | 'ARCHIVED';

/** Filters for listing baselines */
export interface BaselineListFilters {
  status?: BaselineStatus | BaselineStatus[];
  fromDate?: Date;
  toDate?: Date;
  createdBy?: string;
}

/** Pagination options for baseline listing */
export interface BaselinePaginationOptions {
  page?: number;
  pageSize?: number;
  sortBy?: 'baselineDate' | 'createdAt' | 'version';
  sortOrder?: 'asc' | 'desc';
}

/** Paginated result for baselines */
export interface PaginatedBaselineResult {
  data: PlanBaseline[];
  total: number;
  page: number;
  pageSize: number;
  totalPages: number;
}

/** Request to publish a new baseline */
export interface PublishBaselineRequest {
  name: string;
  description?: string;
  userId: string;
  horizonYears?: number; // Default: 10 years
}

/** Result of plan validation for publishing */
export interface PlanValidationResult {
  valid: boolean;
  conflicts: PlanConflict[];
  warnings: PlanWarning[];
}

/** A conflict that prevents baseline publication */
export interface PlanConflict {
  type: 'OVERDUE_PM' | 'TRACK_CONFLICT' | 'MATERIAL_BLOCK' | 'GROUNDED_TRAIN';
  trainId?: string;
  trainNumber?: string;
  pmScheduleId?: string;
  description: string;
}

/** A warning that doesn't prevent publication but should be noted */
export interface PlanWarning {
  type: 'APPROACHING_COMPLIANCE' | 'LOW_MATERIAL' | 'HIGH_UTILIZATION';
  trainId?: string;
  trainNumber?: string;
  description: string;
}

/** Internal mileage projection data */
interface MileageProjectionData {
  trainId: string;
  date: Date;
  projectedKm: number;
  dailyRate: number;
}

/** Baseline summary statistics */
export interface BaselineSummary {
  id: string;
  name: string;
  version: string;
  status: BaselineStatus;
  baselineDate: string;
  horizonEnd: string;
  fleetCount: number | null;
  totalPmScheduled: number | null;
  totalManhourProjected: string | null;
  createdAt: Date | null;
  publishedAt: Date | null;
}

/** PM schedule snapshot with train info */
export interface BaselinePmScheduleWithTrain extends BaselinePmSchedule {
  trainNumber?: string;
  pmCode?: string;
  depotCode?: string;
}

/** Mileage projection with train info */
export interface BaselineMileageProjectionWithTrain extends BaselineMileageProjection {
  trainNumber?: string;
}

// =============================================================================
// Singleton instance
// =============================================================================

let instance: BaselineService | null = null;

/**
 * Get the singleton BaselineService instance
 */
export function getBaselineService(): BaselineService {
  if (!instance) {
    instance = new BaselineService();
  }
  return instance;
}

// =============================================================================
// BaselineService Implementation
// =============================================================================

/**
 * Baseline Service for managing plan baselines
 *
 * @example
 * ```typescript
 * const baselineService = getBaselineService();
 *
 * // Publish a new baseline
 * const baseline = await baselineService.publishBaseline({
 *   name: 'Q1 2026 Plan',
 *   description: 'Quarterly plan baseline',
 *   userId: 'user-123'
 * });
 *
 * // Get latest published baseline
 * const latest = await baselineService.getLatestBaseline();
 *
 * // Get PM schedule snapshot
 * const pmSchedule = await baselineService.getBaselinePmSchedule(baseline.id);
 * ```
 */
export class BaselineService extends BaseService {
  /** Default projection horizon in years */
  private readonly DEFAULT_HORIZON_YEARS = 10;

  /** Default daily mileage when no history available (km) */
  private readonly DEFAULT_DAILY_KM = 150;

  /** Days of mileage history to use for average calculation */
  private readonly MILEAGE_HISTORY_DAYS = 30;

  constructor() {
    super({ name: 'baseline-service' });
  }

  // ===========================================================================
  // Public Methods
  // ===========================================================================

  /**
   * Publish a new baseline from the current plan state
   *
   * This operation:
   * 1. Validates the current plan for critical conflicts
   * 2. Generates a version number
   * 3. Creates the baseline record
   * 4. Snapshots the PM schedule (SCHEDULED and IN_PROGRESS items)
   * 5. Generates mileage projections at monthly intervals
   * 6. Supersedes any previous published baseline
   * 7. Records audit log
   *
   * @throws ValidationError if plan has critical conflicts
   * @throws BusinessRuleError if baseline cannot be created
   */
  async publishBaseline(request: PublishBaselineRequest): Promise<PlanBaseline> {
    return this.traced('publishBaseline', async (span) => {
      span.setAttribute('baseline.name', request.name);
      span.setAttribute(MmsAttributes.USER_ID, request.userId);

      // 1. Validate current plan
      const validation = await this.validatePlanForPublishing();
      if (!validation.valid) {
        this.log.warn(
          { conflicts: validation.conflicts },
          'Cannot publish baseline due to critical conflicts'
        );
        throw new ValidationError(
          'Cannot publish baseline with critical conflicts',
          { context: { conflicts: validation.conflicts } }
        );
      }

      // Log warnings but continue
      if (validation.warnings.length > 0) {
        this.log.info(
          { warnings: validation.warnings },
          `Publishing baseline with ${validation.warnings.length} warnings`
        );
      }

      // 2. Get latest baseline for version increment
      const latestBaseline = await this.getLatestBaseline();
      const version = this.incrementVersion(latestBaseline?.version ?? 'v0.0');
      span.setAttribute('baseline.version', version);

      const horizonYears = request.horizonYears ?? this.DEFAULT_HORIZON_YEARS;
      const baselineDate = new Date();
      const horizonEnd = addYears(baselineDate, horizonYears);

      // 3. Create baseline in transaction
      const baseline = await this.inTransaction(
        'publishBaseline',
        async (tx, txSpan) => {
          // Get metrics for the baseline
          const fleetCount = await this.getActiveTrainCount();
          const pmCount = await this.getScheduledPMCount();
          const manhours = await this.getTotalProjectedHours();

          txSpan.setAttribute('baseline.fleetCount', fleetCount);
          txSpan.setAttribute('baseline.pmCount', pmCount);

          // Create baseline record
          const [baselineRecord] = await tx
            .insert(planBaselines)
            .values({
              name: request.name,
              description: request.description ?? null,
              version,
              baselineDate: format(baselineDate, 'yyyy-MM-dd'),
              horizonEnd: format(horizonEnd, 'yyyy-MM-dd'),
              status: 'PUBLISHED',
              createdBy: request.userId,
              publishedBy: request.userId,
              publishedAt: new Date(),
              fleetCount,
              totalPmScheduled: pmCount,
              totalManhourProjected: manhours.toString(),
            })
            .returning();

          this.log.info(
            { baselineId: baselineRecord.id, version },
            'Created baseline record'
          );

          // Snapshot PM schedule
          const pmSnapshotCount = await this.snapshotPmSchedule(tx, baselineRecord.id);
          txSpan.setAttribute('baseline.pmSnapshotCount', pmSnapshotCount);

          // Generate and store mileage projections
          const projections = await this.generateMileageProjections(horizonEnd);

          if (projections.length > 0) {
            // Batch insert projections for performance
            const BATCH_SIZE = 500;
            for (let i = 0; i < projections.length; i += BATCH_SIZE) {
              const batch = projections.slice(i, i + BATCH_SIZE);
              await tx.insert(baselineMileageProjection).values(
                batch.map((proj) => ({
                  baselineId: baselineRecord.id,
                  trainId: proj.trainId,
                  projectionDate: format(proj.date, 'yyyy-MM-dd'),
                  projectedCumulativeKm: proj.projectedKm,
                  dailyRateKm: proj.dailyRate,
                }))
              );
            }
          }

          txSpan.setAttribute('baseline.mileageProjections', projections.length);

          // Supersede previous baseline
          if (latestBaseline) {
            await tx
              .update(planBaselines)
              .set({
                status: 'SUPERSEDED',
                supersededBy: baselineRecord.id,
                supersededAt: new Date(),
              })
              .where(eq(planBaselines.id, latestBaseline.id));

            this.log.info(
              { supersededId: latestBaseline.id, newId: baselineRecord.id },
              'Superseded previous baseline'
            );
          }

          // Record audit log
          await tx.insert(auditLog).values({
            entityType: 'plan_baseline',
            entityId: baselineRecord.id,
            action: 'PUBLISH',
            userId: request.userId,
            newValues: {
              name: request.name,
              version,
              description: request.description,
              fleetCount,
              pmCount,
            },
            complianceFlags: ['PLANNING'],
          });

          return baselineRecord;
        }
      );

      this.log.info(
        { baselineId: baseline.id, version: baseline.version },
        'Published new baseline successfully'
      );

      return baseline;
    });
  }

  /**
   * Get the latest published baseline
   *
   * @returns The most recent PUBLISHED baseline, or null if none exists
   */
  async getLatestBaseline(): Promise<PlanBaseline | null> {
    return this.traced('getLatestBaseline', async (span) => {
      const result = await this.db
        .select()
        .from(planBaselines)
        .where(eq(planBaselines.status, 'PUBLISHED'))
        .orderBy(desc(planBaselines.publishedAt))
        .limit(1);

      const baseline = result[0] ?? null;

      if (baseline) {
        span.setAttribute(MmsAttributes.BASELINE_ID, baseline.id);
        span.setAttribute('baseline.version', baseline.version);
      }

      return baseline;
    });
  }

  /**
   * Get a baseline by ID
   *
   * @throws NotFoundError if baseline doesn't exist
   */
  async getBaselineById(baselineId: string): Promise<PlanBaseline> {
    return this.traced('getBaselineById', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);

      const result = await this.db
        .select()
        .from(planBaselines)
        .where(eq(planBaselines.id, baselineId))
        .limit(1);

      const baseline = result[0];
      if (!baseline) {
        throw new NotFoundError(`Baseline not found: ${baselineId}`);
      }

      return baseline;
    });
  }

  /**
   * List baselines with optional filtering and pagination
   */
  async listBaselines(
    filters?: BaselineListFilters,
    pagination?: BaselinePaginationOptions
  ): Promise<PaginatedBaselineResult> {
    return this.traced('listBaselines', async (span) => {
      const page = pagination?.page ?? 1;
      const pageSize = pagination?.pageSize ?? 20;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions: ReturnType<typeof eq>[] = [];

      if (filters?.status) {
        const statuses = Array.isArray(filters.status)
          ? filters.status
          : [filters.status];
        conditions.push(inArray(planBaselines.status, statuses));
      }

      if (filters?.fromDate) {
        conditions.push(
          gte(planBaselines.baselineDate, format(filters.fromDate, 'yyyy-MM-dd'))
        );
      }

      if (filters?.createdBy) {
        conditions.push(eq(planBaselines.createdBy, filters.createdBy));
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(planBaselines)
        .where(whereClause);

      // Determine sort order
      const sortColumn =
        pagination?.sortBy === 'baselineDate'
          ? planBaselines.baselineDate
          : pagination?.sortBy === 'version'
          ? planBaselines.version
          : planBaselines.createdAt;

      // Get paginated results
      const data = await this.db
        .select()
        .from(planBaselines)
        .where(whereClause)
        .orderBy(pagination?.sortOrder === 'asc' ? sortColumn : desc(sortColumn))
        .limit(pageSize)
        .offset(offset);

      span.setAttribute('baseline.resultCount', data.length);
      span.setAttribute('baseline.totalCount', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

  /**
   * Get PM schedule snapshot for a baseline
   */
  async getBaselinePmSchedule(
    baselineId: string,
    pagination?: { page?: number; pageSize?: number }
  ): Promise<{ data: BaselinePmSchedule[]; total: number }> {
    return this.traced('getBaselinePmSchedule', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);

      // Verify baseline exists
      await this.getBaselineById(baselineId);

      const page = pagination?.page ?? 1;
      const pageSize = pagination?.pageSize ?? 100;
      const offset = (page - 1) * pageSize;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(baselinePmSchedule)
        .where(eq(baselinePmSchedule.baselineId, baselineId));

      // Get paginated data
      const data = await this.db
        .select()
        .from(baselinePmSchedule)
        .where(eq(baselinePmSchedule.baselineId, baselineId))
        .orderBy(baselinePmSchedule.projectedDate)
        .limit(pageSize)
        .offset(offset);

      span.setAttribute('baseline.pmCount', data.length);

      return { data, total: totalCount };
    });
  }

  /**
   * Get mileage projections for a baseline
   */
  async getMileageProjections(
    baselineId: string,
    trainId?: string,
    pagination?: { page?: number; pageSize?: number }
  ): Promise<{ data: BaselineMileageProjection[]; total: number }> {
    return this.traced('getMileageProjections', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);
      if (trainId) {
        span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      }

      // Verify baseline exists
      await this.getBaselineById(baselineId);

      const page = pagination?.page ?? 1;
      const pageSize = pagination?.pageSize ?? 100;
      const offset = (page - 1) * pageSize;

      // Build where conditions
      const conditions = [eq(baselineMileageProjection.baselineId, baselineId)];
      if (trainId) {
        conditions.push(eq(baselineMileageProjection.trainId, trainId));
      }

      const whereClause = and(...conditions);

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(baselineMileageProjection)
        .where(whereClause);

      // Get paginated data
      const data = await this.db
        .select()
        .from(baselineMileageProjection)
        .where(whereClause)
        .orderBy(
          baselineMileageProjection.trainId,
          baselineMileageProjection.projectionDate
        )
        .limit(pageSize)
        .offset(offset);

      span.setAttribute('baseline.projectionCount', data.length);

      return { data, total: totalCount };
    });
  }

  /**
   * Get baseline summary for display
   */
  async getBaselineSummary(baselineId: string): Promise<BaselineSummary> {
    return this.traced('getBaselineSummary', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);

      const baseline = await this.getBaselineById(baselineId);

      return {
        id: baseline.id,
        name: baseline.name,
        version: baseline.version,
        status: baseline.status as BaselineStatus,
        baselineDate: baseline.baselineDate,
        horizonEnd: baseline.horizonEnd,
        fleetCount: baseline.fleetCount,
        totalPmScheduled: baseline.totalPmScheduled,
        totalManhourProjected: baseline.totalManhourProjected,
        createdAt: baseline.createdAt,
        publishedAt: baseline.publishedAt,
      };
    });
  }

  /**
   * Archive a superseded baseline
   *
   * Archived baselines are retained for audit purposes but excluded
   * from normal queries.
   */
  async archiveBaseline(baselineId: string, userId: string): Promise<PlanBaseline> {
    return this.traced('archiveBaseline', async (span) => {
      span.setAttribute(MmsAttributes.BASELINE_ID, baselineId);
      span.setAttribute(MmsAttributes.USER_ID, userId);

      const baseline = await this.getBaselineById(baselineId);

      if (baseline.status === 'PUBLISHED') {
        throw new BusinessRuleError(
          'Cannot archive published baseline. Publish a new baseline first to supersede it.'
        );
      }

      if (baseline.status === 'ARCHIVED') {
        return baseline; // Already archived
      }

      const [updated] = await this.db
        .update(planBaselines)
        .set({ status: 'ARCHIVED' })
        .where(eq(planBaselines.id, baselineId))
        .returning();

      // Audit log
      await this.db.insert(auditLog).values({
        entityType: 'plan_baseline',
        entityId: baselineId,
        action: 'UPDATE',
        userId,
        oldValues: { status: baseline.status },
        newValues: { status: 'ARCHIVED' },
      });

      this.log.info({ baselineId }, 'Archived baseline');

      return updated;
    });
  }

  // ===========================================================================
  // Private Helper Methods
  // ===========================================================================

  /**
   * Validate the current plan for publishing
   *
   * Checks for critical conflicts that prevent baseline publication:
   * - Overdue PMs (past compliance window)
   * - Track conflicts (double-booked tracks)
   * - Material blocks (missing critical materials)
   * - Grounded trains with scheduled PMs
   */
  private async validatePlanForPublishing(): Promise<PlanValidationResult> {
    return this.traced('validatePlanForPublishing', async (span) => {
      const conflicts: PlanConflict[] = [];
      const warnings: PlanWarning[] = [];
      const today = new Date();
      const todayStr = format(today, 'yyyy-MM-dd');

      // Check for overdue PMs (constraint_end < today and status = SCHEDULED)
      const overduePms = await this.db
        .select({
          id: pmSchedule.id,
          trainId: pmSchedule.trainId,
          constraintEnd: pmSchedule.constraintEnd,
        })
        .from(pmSchedule)
        .where(
          and(
            eq(pmSchedule.status, 'SCHEDULED'),
            sql`${pmSchedule.constraintEnd} < ${todayStr}`,
            sql`${pmSchedule.scenarioId} IS NULL`
          )
        )
        .limit(50);

      for (const pm of overduePms) {
        // Get train number for better error messages
        const train = await this.db
          .select({ trainNumber: trains.trainNumber })
          .from(trains)
          .where(eq(trains.id, pm.trainId))
          .limit(1);

        conflicts.push({
          type: 'OVERDUE_PM',
          trainId: pm.trainId,
          trainNumber: train[0]?.trainNumber,
          pmScheduleId: pm.id,
          description: `PM is overdue (compliance window ended ${pm.constraintEnd})`,
        });
      }

      // Check for grounded trains with scheduled PMs
      const groundedWithPms = await this.db
        .select({
          trainId: trains.id,
          trainNumber: trains.trainNumber,
          pmScheduleId: pmSchedule.id,
        })
        .from(trains)
        .innerJoin(pmSchedule, eq(trains.id, pmSchedule.trainId))
        .where(
          and(
            eq(trains.fitnessStatus, 'GROUNDED'),
            eq(trains.active, true),
            eq(pmSchedule.status, 'SCHEDULED'),
            sql`${pmSchedule.scenarioId} IS NULL`
          )
        )
        .limit(20);

      for (const item of groundedWithPms) {
        conflicts.push({
          type: 'GROUNDED_TRAIN',
          trainId: item.trainId,
          trainNumber: item.trainNumber,
          pmScheduleId: item.pmScheduleId,
          description: 'Train is grounded but has scheduled PMs',
        });
      }

      span.setAttribute('baseline.conflictCount', conflicts.length);
      span.setAttribute('baseline.warningCount', warnings.length);

      return {
        valid: conflicts.length === 0,
        conflicts,
        warnings,
      };
    });
  }

  /**
   * Increment version number
   *
   * Version format: vMajor.Minor (e.g., v1.0, v1.1, v2.0)
   * Increments minor version by default.
   */
  private incrementVersion(currentVersion: string | null): string {
    if (!currentVersion) {
      return 'v1.0';
    }

    // Parse current version (vX.Y format)
    const match = currentVersion.match(/^v?(\d+)\.(\d+)$/);
    if (!match) {
      return 'v1.0';
    }

    const major = parseInt(match[1], 10);
    const minor = parseInt(match[2], 10);

    // Increment minor, or increment major if minor >= 99
    if (minor >= 99) {
      return `v${major + 1}.0`;
    }

    return `v${major}.${minor + 1}`;
  }

  /**
   * Get count of active trains
   */
  private async getActiveTrainCount(): Promise<number> {
    const [{ trainCount }] = await this.db
      .select({ trainCount: count() })
      .from(trains)
      .where(eq(trains.active, true));

    return trainCount;
  }

  /**
   * Get count of scheduled PM items
   */
  private async getScheduledPMCount(): Promise<number> {
    const today = format(new Date(), 'yyyy-MM-dd');

    const [{ pmCount }] = await this.db
      .select({ pmCount: count() })
      .from(pmSchedule)
      .where(
        and(
          inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
          sql`${pmSchedule.scenarioId} IS NULL`,
          sql`${pmSchedule.targetDate} >= ${today}`
        )
      );

    return pmCount;
  }

  /**
   * Get total projected man-hours
   */
  private async getTotalProjectedHours(): Promise<number> {
    const today = format(new Date(), 'yyyy-MM-dd');

    const result = await this.db
      .select({
        totalHours: sql<string>`COALESCE(SUM(${pmSchedule.assignedHours}), 0)`,
      })
      .from(pmSchedule)
      .where(
        and(
          inArray(pmSchedule.status, ['SCHEDULED', 'IN_PROGRESS']),
          sql`${pmSchedule.scenarioId} IS NULL`,
          sql`${pmSchedule.targetDate} >= ${today}`
        )
      );

    return parseFloat(result[0]?.totalHours ?? '0');
  }

  /**
   * Snapshot the current PM schedule into the baseline
   *
   * Copies all SCHEDULED and IN_PROGRESS PM items (production only, not scenarios)
   * to the baseline_pm_schedule table.
   */
  private async snapshotPmSchedule(
    tx: Parameters<Parameters<typeof this.inTransaction>[1]>[0],
    baselineId: string
  ): Promise<number> {
    const today = format(new Date(), 'yyyy-MM-dd');

    // Use raw SQL for efficient bulk insert
    await tx.execute(sql`
      INSERT INTO baseline_pm_schedule
        (baseline_id, train_id, pm_type_id, projected_date, projected_mileage_km, assigned_depot_id, assigned_hours)
      SELECT
        ${baselineId},
        train_id,
        pm_type_id,
        target_date,
        target_mileage_km,
        assigned_depot_id,
        assigned_hours
      FROM pm_schedule
      WHERE scenario_id IS NULL
        AND status IN ('SCHEDULED', 'IN_PROGRESS')
        AND target_date >= ${today}
    `);

    // Get count of inserted rows
    const [{ insertCount }] = await tx
      .select({ insertCount: count() })
      .from(baselinePmSchedule)
      .where(eq(baselinePmSchedule.baselineId, baselineId));

    return insertCount;
  }

  /**
   * Generate mileage projections for all active trains
   *
   * Projects mileage forward at monthly intervals using:
   * 1. Average daily mileage from last 30 days (if available)
   * 2. Default daily mileage (150 km) if no history
   */
  private async generateMileageProjections(
    horizonEnd: Date
  ): Promise<MileageProjectionData[]> {
    return this.traced('generateMileageProjections', async (span) => {
      // Get all active trains with their current mileage
      const activeTrains = await this.db
        .select({
          id: trains.id,
          trainNumber: trains.trainNumber,
          currentMileageKm: trains.currentMileageKm,
        })
        .from(trains)
        .where(eq(trains.active, true));

      span.setAttribute('baseline.trainCount', activeTrains.length);

      const projections: MileageProjectionData[] = [];
      const cutoffDate = subDays(new Date(), this.MILEAGE_HISTORY_DAYS);
      const cutoffDateStr = format(cutoffDate, 'yyyy-MM-dd');

      for (const train of activeTrains) {
        // Calculate average daily mileage from recent history
        const recentMileage = await this.db
          .select({
            avgDailyKm: sql<string>`AVG(daily_km)`,
            readingCount: count(),
          })
          .from(mileageReadings)
          .where(
            and(
              eq(mileageReadings.trainId, train.id),
              sql`${mileageReadings.readingDate} >= ${cutoffDateStr}`,
              eq(mileageReadings.validationStatus, 'VALID')
            )
          );

        const avgDailyKm =
          recentMileage[0]?.avgDailyKm && recentMileage[0].readingCount > 5
            ? parseFloat(recentMileage[0].avgDailyKm)
            : this.DEFAULT_DAILY_KM;

        // Project forward at monthly intervals
        let currentKm = train.currentMileageKm ?? 0;
        let currentDate = new Date();

        while (currentDate < horizonEnd) {
          currentDate = addMonths(currentDate, 1);
          currentKm += avgDailyKm * 30;

          projections.push({
            trainId: train.id,
            date: new Date(currentDate),
            projectedKm: Math.round(currentKm),
            dailyRate: Math.round(avgDailyKm),
          });
        }
      }

      span.setAttribute('baseline.totalProjections', projections.length);

      return projections;
    });
  }
}

