     1→/**
     2→ * MMS Fleet Service
     3→ *
     4→ * Core domain service for fleet asset management.
     5→ * Provides CRUD operations for depots, fleets, trains, routes, and tracks.
     6→ * Manages train lifecycle states and mileage tracking.
     7→ *
     8→ * Business rules:
     9→ * - Train fitness transitions: FIT <-> RESTRICTED <-> GROUNDED
    10→ * - Mileage accumulation is additive (never decreases except for corrections)
    11→ * - Fleet mileage balancing: target = fleet average, variance = current - target
    12→ * - Active entities can be deactivated but not deleted (audit compliance)
    13→ *
    14→ * @see specs/003-database-schema.md Section 3.2 (Core Fleet Domain)
    15→ */
    16→
    17→import { eq, and, inArray, sql, desc, asc, count, avg, sum, type SQL } from 'drizzle-orm';
    18→import { BaseService, MmsAttributes } from '../lib/services/base';
    19→import {
    20→  depots,
    21→  fleets,
    22→  trains,
    23→  routes,
    24→  tracks,
    25→  trainComponents,
    26→  componentInstallations,
    27→  componentPmTracking,
    28→  type Depot,
    29→  type NewDepot,
    30→  type Fleet,
    31→  type NewFleet,
    32→  type Train,
    33→  type NewTrain,
    34→  type Route,
    35→  type NewRoute,
    36→  type Track,
    37→  type NewTrack,
    38→  type TrainComponent,
    39→  type NewTrainComponent,
    40→  type ComponentInstallation,
    41→  type NewComponentInstallation,
    42→  type ComponentPmTracking,
    43→} from '../lib/db/schema';
    44→import {
    45→  NotFoundError,
    46→  TrainNotFoundError,
    47→  ValidationError,
    48→  DuplicateError,
    49→  BusinessRuleError,
    50→} from '../lib/errors';
    51→
    52→// =============================================================================
    53→// Types
    54→// =============================================================================
    55→
    56→/** Valid fitness status transitions */
    57→type FitnessStatus = 'FIT' | 'RESTRICTED' | 'GROUNDED';
    58→
    59→/** Query filters for listing trains */
    60→export interface TrainListFilters {
    61→  fleetId?: string;
    62→  depotId?: string;
    63→  fitnessStatus?: FitnessStatus | FitnessStatus[];
    64→  active?: boolean;
    65→  trainNumbers?: string[];
    66→}
    67→
    68→/** Query filters for listing fleets */
    69→export interface FleetListFilters {
    70→  baseDepotId?: string;
    71→  manufacturer?: string;
    72→  active?: boolean;
    73→}
    74→
    75→/** Pagination options */
    76→export interface PaginationOptions {
    77→  page?: number;
    78→  pageSize?: number;
    79→  sortBy?: string;
    80→  sortOrder?: 'asc' | 'desc';
    81→}
    82→
    83→/** Paginated result */
    84→export interface PaginatedResult<T> {
    85→  data: T[];
    86→  total: number;
    87→  page: number;
    88→  pageSize: number;
    89→  totalPages: number;
    90→}
    91→
    92→/** Fleet statistics */
    93→export interface FleetStatistics {
    94→  fleetId: string;
    95→  fleetCode: string;
    96→  totalTrains: number;
    97→  activeTrains: number;
    98→  fitTrains: number;
    99→  restrictedTrains: number;
   100→  groundedTrains: number;
   101→  totalMileageKm: number;
   102→  averageMileageKm: number;
   103→  minMileageKm: number;
   104→  maxMileageKm: number;
   105→  mileageStdDevKm: number;
   106→}
   107→
   108→/** Train with fleet details */
   109→export interface TrainWithFleet extends Train {
   110→  fleet: Fleet | null;
   111→  currentDepot: Depot | null;
   112→  homeDepot: Depot | null;
