  1341→  /**
  1342→   * Check if train numbers exist (for ingestion validation)
  1343→   */
  1344→  async validateTrainNumbers(trainNumbers: string[]): Promise<{
  1345→    valid: string[];
  1346→    invalid: string[];
  1347→  }> {
  1348→    return this.traced('validateTrainNumbers', async (span) => {
  1349→      span.setAttribute('input.count', trainNumbers.length);
  1350→
  1351→      if (trainNumbers.length === 0) {
  1352→        return { valid: [], invalid: [] };
  1353→      }
  1354→
  1355→      const existing = await this.db.query.trains.findMany({
  1356→        where: inArray(trains.trainNumber, trainNumbers),
  1357→        columns: { trainNumber: true },
  1358→      });
  1359→
  1360→      const existingSet = new Set(existing.map((t) => t.trainNumber));
  1361→      const valid: string[] = [];
  1362→      const invalid: string[] = [];
  1363→
  1364→      for (const num of trainNumbers) {
  1365→        if (existingSet.has(num)) {
  1366→          valid.push(num);
  1367→        } else {
  1368→          invalid.push(num);
  1369→        }
  1370→      }
  1371→
  1372→      span.setAttribute('result.valid', valid.length);
  1373→      span.setAttribute('result.invalid', invalid.length);
  1374→
  1375→      return { valid, invalid };
  1376→    });
