  2131→          totalMileage,
  2132→          installationsCalculated,
  2133→        },
  2134→        'Component mileage recalculated'
  2135→      );
  2136→
  2137→      return {
  2138→        componentId,
  2139→        serialNumber: component.serialNumber,
  2140→        totalComponentMileageKm: totalMileage,
  2141→        installationsCalculated,
  2142→      };
  2143→    });
  2144→  }
  2145→
  2146→  /**
  2147→   * Get installation history for a component
  2148→   */
  2149→  async getComponentInstallationHistory(componentId: string): Promise<ComponentInstallation[]> {
  2150→    return this.traced('getComponentInstallationHistory', async (span) => {
  2151→      span.setAttribute('component.id', componentId);
  2152→
  2153→      // Verify component exists
  2154→      const component = await this.db.query.trainComponents.findFirst({
  2155→        where: eq(trainComponents.id, componentId),
  2156→      });
  2157→
  2158→      if (!component) {
  2159→        throw new NotFoundError(`Component not found: ${componentId}`, {
  2160→          entityType: 'component',
  2161→          entityId: componentId,
  2162→        });
  2163→      }
  2164→
  2165→      const history = await this.db.query.componentInstallations.findMany({
  2166→        where: eq(componentInstallations.componentId, componentId),
  2167→        orderBy: desc(componentInstallations.installedDate),
  2168→      });
  2169→
  2170→      span.setAttribute('result.count', history.length);
  2171→      return history;
  2172→    });
  2173→  }
  2174→
  2175→  /**
  2176→   * Get all components currently installed on a train
  2177→   */
  2178→  async getTrainComponents(trainId: string): Promise<TrainComponent[]> {
  2179→    return this.traced('getTrainComponents', async (span) => {
  2180→      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
  2181→
  2182→      // Verify train exists
  2183→      const train = await this.db.query.trains.findFirst({
  2184→        where: eq(trains.id, trainId),
  2185→      });
  2186→
  2187→      if (!train) {
  2188→        throw new TrainNotFoundError(trainId);
  2189→      }
  2190→
  2191→      const components = await this.db.query.trainComponents.findMany({
  2192→        where: eq(trainComponents.currentTrainId, trainId),
  2193→        orderBy: [asc(trainComponents.componentType), asc(trainComponents.currentPosition)],
  2194→      });
  2195→
  2196→      span.setAttribute('result.count', components.length);
  2197→      return components;
  2198→    });
  2199→  }
  2200→
  2201→  // ===========================================================================
  2202→  // Component PM Tracking
  2203→  // ===========================================================================
  2204→
  2205→  /**
  2206→   * Get PM tracking status for a component
  2207→   */
  2208→  async getComponentPmStatus(componentId: string): Promise<ComponentPmTracking[]> {
  2209→    return this.traced('getComponentPmStatus', async (span) => {
  2210→      span.setAttribute('component.id', componentId);
  2211→
  2212→      // Verify component exists
  2213→      const component = await this.db.query.trainComponents.findFirst({
  2214→        where: eq(trainComponents.id, componentId),
  2215→      });
  2216→
  2217→      if (!component) {
  2218→        throw new NotFoundError(`Component not found: ${componentId}`, {
  2219→          entityType: 'component',
  2220→          entityId: componentId,
  2221→        });
  2222→      }
  2223→
  2224→      const pmStatus = await this.db.query.componentPmTracking.findMany({
  2225→        where: eq(componentPmTracking.componentId, componentId),
  2226→      });
  2227→
  2228→      span.setAttribute('result.count', pmStatus.length);
  2229→      return pmStatus;
  2230→    });
  2231→  }
  2232→
  2233→  /**
  2234→   * Update or create PM tracking status for a component
  2235→   */
  2236→  async updateComponentPmStatus(
  2237→    componentId: string,
  2238→    pmTypeId: string,
  2239→    lastPmDate: string,
  2240→    lastPmMileageKm: number
  2241→  ): Promise<ComponentPmTracking> {
  2242→    return this.inTransaction('updateComponentPmStatus', async (tx, span) => {
  2243→      span.setAttribute('component.id', componentId);
  2244→      span.setAttribute('pmType.id', pmTypeId);
  2245→
  2246→      // Verify component exists
