  /**
   * Get comprehensive statistics for a fleet
   */
  async getFleetStatistics(fleetId: string): Promise<FleetStatistics> {
    return this.traced('getFleetStatistics', async (span) => {
      span.setAttribute(MmsAttributes.FLEET_ID, fleetId);

      // Verify fleet exists
      const fleet = await this.db.query.fleets.findFirst({
        where: eq(fleets.id, fleetId),
      });

      if (!fleet) {
        throw new NotFoundError(`Fleet not found: ${fleetId}`, {
          entityType: 'fleet',
          entityId: fleetId,
        });
      }

      // Get all stats in one query
      const statsQuery = await this.db
        .select({
          totalTrains: count(),
          totalMileageKm: sum(trains.currentMileageKm),
          averageMileageKm: avg(trains.currentMileageKm),
          minMileageKm: sql<number>`MIN(${trains.currentMileageKm})`,
          maxMileageKm: sql<number>`MAX(${trains.currentMileageKm})`,
          stdDevMileageKm: sql<number>`STDDEV(${trains.currentMileageKm})`,
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)));

      const stats = statsQuery[0];

      // Get counts by fitness status
      const fitnessCounts = await this.db
        .select({
          status: trains.fitnessStatus,
          count: count(),
        })
        .from(trains)
        .where(and(eq(trains.fleetId, fleetId), eq(trains.active, true)))
        .groupBy(trains.fitnessStatus);

      const statusMap = new Map(fitnessCounts.map((fc) => [fc.status, fc.count]));

      const result: FleetStatistics = {
        fleetId,
        fleetCode: fleet.code,
        totalTrains: Number(stats.totalTrains) || 0,
        activeTrains: Number(stats.totalTrains) || 0,
        fitTrains: statusMap.get('FIT') || 0,
        restrictedTrains: statusMap.get('RESTRICTED') || 0,
        groundedTrains: statusMap.get('GROUNDED') || 0,
        totalMileageKm: Number(stats.totalMileageKm) || 0,
        averageMileageKm: Math.round(Number(stats.averageMileageKm) || 0),
        minMileageKm: Number(stats.minMileageKm) || 0,
        maxMileageKm: Number(stats.maxMileageKm) || 0,
        mileageStdDevKm: Math.round(Number(stats.stdDevMileageKm) || 0),
      };

      span.setAttribute('stats.totalTrains', result.totalTrains);
      span.setAttribute('stats.fitTrains', result.fitTrains);
      span.setAttribute('stats.avgMileage', result.averageMileageKm);

      return result;
    });
  }

  /**
   * Get statistics for all fleets
   */
  async getAllFleetStatistics(): Promise<FleetStatistics[]> {
    return this.traced('getAllFleetStatistics', async (span) => {
      const allFleets = await this.db.query.fleets.findMany({
