  /**
   * Check if train numbers exist (for ingestion validation)
   */
  async validateTrainNumbers(trainNumbers: string[]): Promise<{
    valid: string[];
    invalid: string[];
  }> {
    return this.traced('validateTrainNumbers', async (span) => {
      span.setAttribute('input.count', trainNumbers.length);

      if (trainNumbers.length === 0) {
        return { valid: [], invalid: [] };
      }

      const existing = await this.db.query.trains.findMany({
        where: inArray(trains.trainNumber, trainNumbers),
        columns: { trainNumber: true },
      });

      const existingSet = new Set(existing.map((t) => t.trainNumber));
      const valid: string[] = [];
      const invalid: string[] = [];

      for (const num of trainNumbers) {
        if (existingSet.has(num)) {
          valid.push(num);
        } else {
          invalid.push(num);
        }
      }

      span.setAttribute('result.valid', valid.length);
      span.setAttribute('result.invalid', invalid.length);

      return { valid, invalid };
    });
  }

