  /**
   * List components with optional filters
   */
  async listComponents(
    filters?: ComponentListFilters,
    pagination?: PaginationOptions
  ): Promise<PaginatedResult<TrainComponent>> {
    return this.traced('listComponents', async (span) => {
      const conditions: SQL<unknown>[] = [];

      if (filters?.componentType) {
        conditions.push(eq(trainComponents.componentType, filters.componentType));
      }
      if (filters?.status) {
        if (Array.isArray(filters.status)) {
          conditions.push(inArray(trainComponents.status, filters.status));
        } else {
          conditions.push(eq(trainComponents.status, filters.status));
        }
      }
      if (filters?.trainId) {
        conditions.push(eq(trainComponents.currentTrainId, filters.trainId));
      }
      if (filters?.serialNumbers && filters.serialNumbers.length > 0) {
        conditions.push(inArray(trainComponents.serialNumber, filters.serialNumbers));
      }
      if (filters?.hasCurrentTrain !== undefined) {
        if (filters.hasCurrentTrain) {
          conditions.push(sql`${trainComponents.currentTrainId} IS NOT NULL`);
        } else {
          conditions.push(sql`${trainComponents.currentTrainId} IS NULL`);
        }
      }

      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [{ totalCount }] = await this.db
        .select({ totalCount: count() })
        .from(trainComponents)
        .where(whereClause);

      // Apply pagination
      const page = pagination?.page ?? 1;
      const pageSize = Math.min(pagination?.pageSize ?? 50, 500);
      const offset = (page - 1) * pageSize;

      // Determine sort order
      const sortDirection = pagination?.sortOrder === 'desc' ? desc : asc;
      const getOrderBy = () => {
        switch (pagination?.sortBy) {
          case 'mileage':
            return sortDirection(trainComponents.componentMileageKm);
          case 'status':
            return sortDirection(trainComponents.status);
          case 'type':
            return sortDirection(trainComponents.componentType);
          default:
            return sortDirection(trainComponents.serialNumber);
        }
      };

      const data = await this.db.query.trainComponents.findMany({
        where: whereClause,
        orderBy: getOrderBy(),
        limit: pageSize,
        offset,
      });

      span.setAttribute('result.count', data.length);
      span.setAttribute('result.total', totalCount);

      return {
        data,
        total: totalCount,
        page,
        pageSize,
        totalPages: Math.ceil(totalCount / pageSize),
      };
    });
  }

  /**
   * Create a new component
   */
  async createComponent(data: NewTrainComponent): Promise<TrainComponent> {
    return this.inTransaction('createComponent', async (tx, span) => {
      span.setAttribute('component.serialNumber', data.serialNumber);
      span.setAttribute('component.type', data.componentType);

      // Check for duplicate serial number
      const existing = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.serialNumber, data.serialNumber),
      });

      if (existing) {
        throw new DuplicateError(`Component with serial number ${data.serialNumber} already exists`, {
          field: 'serialNumber',
          value: data.serialNumber,
        });
      }

      // Validate current train if provided
      if (data.currentTrainId) {
        const train = await tx.query.trains.findFirst({
          where: eq(trains.id, data.currentTrainId),
        });
        if (!train) {
          throw new ValidationError('Train not found', {
            field: 'currentTrainId',
            context: { trainId: data.currentTrainId },
          });
        }
      }

      const [result] = await tx.insert(trainComponents).values(data).returning();
      span.setAttribute('component.id', result.id);

      this.log.info(
        { componentId: result.id, serialNumber: data.serialNumber, type: data.componentType },
        'Component created'
      );
      return result;
    });
  }

  /**
   * Update an existing component
   */
  async updateComponent(id: string, data: Partial<NewTrainComponent>): Promise<TrainComponent> {
    return this.inTransaction('updateComponent', async (tx, span) => {
      span.setAttribute('component.id', id);

      const existing = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, id),
      });

      if (!existing) {
        throw new NotFoundError(`Component not found: ${id}`, {
          entityType: 'component',
          entityId: id,
        });
      }

      // Check for duplicate serial number if changing
      if (data.serialNumber && data.serialNumber !== existing.serialNumber) {
        const duplicate = await tx.query.trainComponents.findFirst({
          where: eq(trainComponents.serialNumber, data.serialNumber),
        });
        if (duplicate) {
          throw new DuplicateError(`Component with serial number ${data.serialNumber} already exists`, {
            field: 'serialNumber',
            value: data.serialNumber,
          });
        }
      }

      const [result] = await tx
        .update(trainComponents)
        .set({ ...data, updatedAt: new Date() })
        .where(eq(trainComponents.id, id))
        .returning();

      return result;
    });
  }

