  /**
   * Get all components currently installed on a train
   */
  async getTrainComponents(trainId: string): Promise<TrainComponent[]> {
    return this.traced('getTrainComponents', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      // Verify train exists
      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new TrainNotFoundError(trainId);
      }

      const components = await this.db.query.trainComponents.findMany({
        where: eq(trainComponents.currentTrainId, trainId),
        orderBy: [asc(trainComponents.componentType), asc(trainComponents.currentPosition)],
      });

      span.setAttribute('result.count', components.length);
      return components;
    });
  }

  // ===========================================================================
  // Component PM Tracking
  // ===========================================================================

  /**
   * Get PM tracking status for a component
   */
  async getComponentPmStatus(componentId: string): Promise<ComponentPmTracking[]> {
    return this.traced('getComponentPmStatus', async (span) => {
      span.setAttribute('component.id', componentId);

      // Verify component exists
      const component = await this.db.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      const pmStatus = await this.db.query.componentPmTracking.findMany({
        where: eq(componentPmTracking.componentId, componentId),
      });

      span.setAttribute('result.count', pmStatus.length);
      return pmStatus;
    });
  }

  /**
   * Update or create PM tracking status for a component
   */
  async updateComponentPmStatus(
    componentId: string,
    pmTypeId: string,
    lastPmDate: string,
    lastPmMileageKm: number
  ): Promise<ComponentPmTracking> {
    return this.inTransaction('updateComponentPmStatus', async (tx, span) => {
      span.setAttribute('component.id', componentId);
      span.setAttribute('pmType.id', pmTypeId);

      // Verify component exists
      const component = await tx.query.trainComponents.findFirst({
        where: eq(trainComponents.id, componentId),
      });

      if (!component) {
        throw new NotFoundError(`Component not found: ${componentId}`, {
          entityType: 'component',
          entityId: componentId,
        });
      }

      // Check if tracking record exists
      const existing = await tx.query.componentPmTracking.findFirst({
        where: and(
          eq(componentPmTracking.componentId, componentId),
          eq(componentPmTracking.pmTypeId, pmTypeId)
        ),
      });

      if (existing) {
        // Update existing record
        const [result] = await tx
          .update(componentPmTracking)
          .set({
            lastPmDate,
            lastPmMileageKm,
            updatedAt: new Date(),
          })
          .where(eq(componentPmTracking.id, existing.id))
          .returning();

        this.log.info(
          { componentId, pmTypeId, lastPmDate, lastPmMileageKm },
          'Component PM status updated'
        );
        return result;
      } else {
        // Create new record
        const [result] = await tx
          .insert(componentPmTracking)
          .values({
            componentId,
            pmTypeId,
            lastPmDate,
            lastPmMileageKm,
          })
          .returning();

        this.log.info(
          { componentId, pmTypeId, lastPmDate, lastPmMileageKm },
          'Component PM tracking created'
        );
        return result;
      }
    });
  }
}

