/**
 * MMS Ingestion Service
 *
 * Processes daily CSV files containing mileage data.
 * Validates records, handles meter events, and updates the database.
 *
 * Data flow:
 * 1. CSV file arrives via file watcher or API upload
 * 2. File is validated (format, size, structure)
 * 3. Records are parsed and validated in batches
 * 4. Anomalies are detected (NEGATIVE, SPIKE, DUPLICATE)
 * 5. Mileage readings are inserted/updated
 * 6. Train current_mileage_km is updated
 * 7. Fleet mileage targets are recalculated
 *
 * Business rules:
 * - Max file size: 10MB
 * - Expected file pattern: mileage_YYYYMMDD.csv
 * - Batch size: 100 records per transaction
 * - Anomaly thresholds: NEGATIVE < 0, SPIKE > 1000 km/day
 * - Meter adjustments are applied to maintain mileage continuity
 *
 * @see specs/004-domain-services.md Section 4.2
 */

import { eq, and, desc, lte, sql } from 'drizzle-orm';
import * as Papa from 'papaparse';
import * as fs from 'node:fs';
import * as path from 'node:path';
import { BaseService, MmsAttributes } from '../lib/services/base';
import { trains, mileageReadings, meterEvents } from '../lib/db/schema';
import {
  ValidationError,
  FileError,
  BusinessRuleError,
} from '../lib/errors';
import { parseMileageCsvRow } from '../lib/schemas';
import { addJob, QUEUE_NAMES, type IngestionJobData } from '../lib/queue';
import { ingestionMetrics, recordIngestionComplete, recordIngestionAnomaly } from '../lib/metrics';

// =============================================================================
// Constants
// =============================================================================

const MAX_FILE_SIZE_BYTES = 10 * 1024 * 1024; // 10MB
const EXPECTED_FILE_PATTERN = /^mileage_\d{8}\.csv$/;
const BATCH_SIZE = 100;
const SPIKE_THRESHOLD_KM = 1000;
const ALERT_THRESHOLD_HOURS = 2;

// =============================================================================
// Types
// =============================================================================

/** Anomaly types detected during ingestion */
export type AnomalyType = 'NEGATIVE' | 'SPIKE' | 'DUPLICATE' | 'MISSING' | 'FUTURE_DATE' | 'UNKNOWN_TRAIN';

/** A detected anomaly in the mileage data */
export interface AnomalyRecord {
  trainNumber: string;
  readingDate: string;
  type: AnomalyType;
  value: number | null;
  message: string;
  rawReading?: number;
  previousReading?: number;
}

/** Result of meter event detection */
export interface MeterEventRecord {
  trainNumber: string;
  trainId: string;
  eventDate: string;
  eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP';
  oldReading: number;
  newReading: number;
  adjustmentKm: number;
}

/** Configuration for the file watcher */
export interface FileWatcherConfig {
  inboxPath: string;
  processedPath: string;
  quarantinePath: string;
  expectedFilePattern?: RegExp;
  maxFileSizeBytes?: number;
  alertThresholdHours?: number;
  pollIntervalMs?: number;
}

/** Result of file validation */
export interface FileValidationResult {
  valid: boolean;
  errors: string[];
  warnings: string[];
  fileSize: number;
  rowCount?: number;
}

/** Result of ingestion processing */
export interface IngestionResult {
  jobId: string;
  fileName: string;
  totalRecords: number;
  validRecords: number;
  invalidRecords: number;
  anomalies: AnomalyRecord[];
  meterEvents: MeterEventRecord[];
  processingTimeMs: number;
  trainsUpdated: number;
  status: 'SUCCESS' | 'PARTIAL' | 'FAILED';
  errorMessage?: string;
}

/** Internal record type after parsing */
interface ParsedMileageRecord {
  trainNumber: string;
  readingDate: string;
  odometerKm: number;
  rowIndex: number;
}

/** Row validation result */
interface RowValidationResult {
  valid: boolean;
  record?: ParsedMileageRecord;
  error?: string;
  anomaly?: AnomalyRecord;
}

/** Filters for mileage readings query */
export interface MileageReadingFilters {
  trainId?: string;
  fromDate?: string;
  toDate?: string;
  validationStatus?: 'PENDING' | 'VALID' | 'ANOMALY' | 'CORRECTED';
  page?: number;
  pageSize?: number;
}

/** Mileage reading with train information */
export interface MileageReadingWithTrain {
  trainId: string;
  trainNumber: string;
  readingDate: string;
  rawReading: number;
  adjustedReading: number;
  dailyKm: number | null;
  validationStatus: 'PENDING' | 'VALID' | 'ANOMALY' | 'CORRECTED';
  sourceFile: string | null;
}

/** Database-stored anomaly types (subset of AnomalyType) */
export type DbAnomalyType = 'NEGATIVE' | 'SPIKE' | 'MISSING' | 'DUPLICATE';

/** Filters for anomaly query */
export interface AnomalyQueryFilters {
  trainId?: string;
  fromDate?: string;
  toDate?: string;
  anomalyType?: DbAnomalyType;
  page?: number;
  pageSize?: number;
}

/** Anomaly with details for API response */
export interface AnomalyWithDetails {
  trainId: string;
  trainNumber: string;
  readingDate: string;
  anomalyType: DbAnomalyType | null;
  rawReading: number;
  dailyKm: number | null;
  expectedRange: { min: number; max: number };
  suggestedAction: string;
}

// =============================================================================
// Ingestion Service
// =============================================================================

export class IngestionService extends BaseService {
  private lastFileReceivedAt: Date | null = null;

  constructor() {
    super({ name: 'ingestion-service', version: '1.0.0' });
  }

  // ===========================================================================
  // File Validation
  // ===========================================================================

  /**
   * Validate a mileage CSV file before processing
   *
   * Checks:
   * - File exists and is readable
   * - File size within limit
   * - Filename matches expected pattern
   * - CSV structure is valid
   * - Required columns present
   */
  async validateFile(filePath: string): Promise<FileValidationResult> {
    return this.traced('validateFile', async (span) => {
      span.setAttribute('file.path', filePath);

      const errors: string[] = [];
      const warnings: string[] = [];
      const fileName = path.basename(filePath);

      // Check file exists
      if (!fs.existsSync(filePath)) {
        return {
          valid: false,
          errors: [`File not found: ${filePath}`],
          warnings: [],
          fileSize: 0,
        };
      }

      // Check file size
      const stats = fs.statSync(filePath);
      const fileSize = stats.size;
      span.setAttribute('file.size', fileSize);

      if (fileSize === 0) {
        errors.push('File is empty');
      }

      if (fileSize > MAX_FILE_SIZE_BYTES) {
        errors.push(`File size ${fileSize} exceeds maximum ${MAX_FILE_SIZE_BYTES} bytes`);
      }

      // Check filename pattern
      if (!EXPECTED_FILE_PATTERN.test(fileName)) {
        warnings.push(`Filename '${fileName}' does not match expected pattern mileage_YYYYMMDD.csv`);
      }

      // Validate CSV structure (read first 10 lines)
      if (fileSize > 0) {
        try {
          const sample = this.readFirstLines(filePath, 10);
          const structureErrors = this.validateCsvStructure(sample);
          errors.push(...structureErrors);
        } catch (error) {
          errors.push(`Failed to read CSV: ${error instanceof Error ? error.message : 'Unknown error'}`);
        }
      }

      const valid = errors.length === 0;
      span.setAttribute('validation.valid', valid);
      span.setAttribute('validation.errorCount', errors.length);

      return {
        valid,
        errors,
        warnings,
        fileSize,
      };
    });
  }

  /**
   * Read first N lines from a file
   */
  private readFirstLines(filePath: string, lineCount: number): string {
    const content = fs.readFileSync(filePath, 'utf-8');
    const lines = content.split('\n').slice(0, lineCount);
    return lines.join('\n');
  }

  /**
   * Validate CSV structure (headers and format)
   */
  private validateCsvStructure(csvSample: string): string[] {
    const errors: string[] = [];

    const parseResult = Papa.parse(csvSample, {
      header: true,
      skipEmptyLines: true,
    });

    if (parseResult.errors.length > 0) {
      for (const error of parseResult.errors.slice(0, 5)) {
        errors.push(`CSV parse error at row ${error.row ?? 'unknown'}: ${error.message}`);
      }
      return errors;
    }

    // Check required columns
    const headers = parseResult.meta.fields ?? [];
    const requiredColumns = ['train_number', 'reading_date', 'odometer_km'];

    for (const col of requiredColumns) {
      if (!headers.includes(col)) {
        errors.push(`Missing required column: ${col}`);
      }
    }

    return errors;
  }

  // ===========================================================================
  // File Processing
  // ===========================================================================

  /**
   * Queue a file for async processing
   */
  async queueFileForProcessing(
    filePath: string,
    uploadedBy?: string
  ): Promise<{ jobId: string }> {
    return this.traced('queueFileForProcessing', async (span) => {
      span.setAttribute('file.path', filePath);

      // Validate file first
      const validation = await this.validateFile(filePath);

      if (!validation.valid) {
        throw new ValidationError('File validation failed', {
          field: 'file',
          context: {
            errors: validation.errors,
            warnings: validation.warnings,
          },
        });
      }

      const fileName = path.basename(filePath);
      const jobData: IngestionJobData = {
        filePath,
        fileName,
        fileSize: validation.fileSize,
        uploadedBy,
      };

      const { id } = await addJob(
        QUEUE_NAMES.INGESTION,
        'process-mileage-csv',
        jobData,
        {
          attempts: 3,
          backoff: { type: 'exponential', delay: 5000 },
        }
      );

      this.lastFileReceivedAt = new Date();

      this.log.info(
        { jobId: id, fileName, fileSize: validation.fileSize, uploadedBy },
        'File queued for ingestion'
      );

      return { jobId: id };
    });
  }

  /**
   * Process a mileage CSV file (main ingestion entry point)
   *
   * This is the core method called by the ingestion worker.
   */
  async processFile(
    filePath: string,
    jobId: string = crypto.randomUUID()
  ): Promise<IngestionResult> {
    return this.traced('processFile', async (span) => {
      const startTime = Date.now();
      const fileName = path.basename(filePath);

      span.setAttribute(MmsAttributes.INGESTION_FILE, fileName);
      span.setAttribute(MmsAttributes.INGESTION_JOB_ID, jobId);

      ingestionMetrics.filesReceived.inc();

      const result: IngestionResult = {
        jobId,
        fileName,
        totalRecords: 0,
        validRecords: 0,
        invalidRecords: 0,
        anomalies: [],
        meterEvents: [],
        processingTimeMs: 0,
        trainsUpdated: 0,
        status: 'SUCCESS',
      };

      try {
        // Parse CSV
        const records = await this.parseCsv(filePath);
        result.totalRecords = records.length;
        span.setAttribute(MmsAttributes.INGESTION_RECORD_COUNT, records.length);

        ingestionMetrics.recordsProcessed.inc(records.length);

        if (records.length === 0) {
          result.status = 'PARTIAL';
          result.errorMessage = 'No valid records found in CSV';
          this.log.warn({ fileName, jobId }, 'CSV file contains no valid records');
          return result;
        }

        // Process in batches
        const batches = this.chunk(records, BATCH_SIZE);
        const trainIdsUpdated = new Set<string>();

        for (const batch of batches) {
          const batchResult = await this.processBatch(batch, fileName, result);
          for (const trainId of batchResult.trainIdsUpdated) {
            trainIdsUpdated.add(trainId);
          }
        }

        result.trainsUpdated = trainIdsUpdated.size;

        // Update train current mileage for all affected trains
        await this.updateTrainMileage(records, trainIdsUpdated);

        // Determine final status
        if (result.invalidRecords > 0 && result.validRecords > 0) {
          result.status = 'PARTIAL';
        } else if (result.validRecords === 0) {
          result.status = 'FAILED';
          result.errorMessage = 'All records failed validation';
        }

        result.processingTimeMs = Date.now() - startTime;

        span.setAttribute('result.validRecords', result.validRecords);
        span.setAttribute('result.invalidRecords', result.invalidRecords);
        span.setAttribute('result.anomalyCount', result.anomalies.length);
        span.setAttribute('result.status', result.status);

        recordIngestionComplete(result.status, result.processingTimeMs);

        this.log.info(
          {
            jobId,
            fileName,
            totalRecords: result.totalRecords,
            validRecords: result.validRecords,
            invalidRecords: result.invalidRecords,
            anomalies: result.anomalies.length,
            trainsUpdated: result.trainsUpdated,
            processingTimeMs: result.processingTimeMs,
            status: result.status,
          },
          `Ingestion complete: ${result.validRecords}/${result.totalRecords} records processed`
        );

        return result;
      } catch (error) {
        result.processingTimeMs = Date.now() - startTime;
        result.status = 'FAILED';
        result.errorMessage = error instanceof Error ? error.message : 'Unknown error';

        recordIngestionComplete('FAILED', result.processingTimeMs);

        this.log.error(
          { error, jobId, fileName },
          `Ingestion failed: ${result.errorMessage}`
        );

        throw error;
      }
    });
  }

  /**
   * Parse a CSV file and validate each row
   */
  private async parseCsv(filePath: string): Promise<ParsedMileageRecord[]> {
    return this.traced('parseCsv', async (span) => {
      span.setAttribute('file.path', filePath);

      const content = fs.readFileSync(filePath, 'utf-8');

      return new Promise<ParsedMileageRecord[]>((resolve, reject) => {
        const records: ParsedMileageRecord[] = [];
        let rowIndex = 0;

        Papa.parse(content, {
          header: true,
          skipEmptyLines: true,
          complete: (results) => {
            span.setAttribute('parse.rowCount', results.data.length);

            for (const row of results.data) {
              rowIndex++;
              const validation = this.validateRow(row, rowIndex);

              if (validation.valid && validation.record) {
                records.push(validation.record);
              }
            }

            this.log.debug(
              { filePath, totalRows: results.data.length, validRows: records.length },
              'CSV parsing complete'
            );

            resolve(records);
          },
          error: (error: Error) => {
            reject(new FileError(`CSV parse error: ${error.message}`, {
              filePath,
              operation: 'parse',
            }));
          },
        });
      });
    });
  }

  /**
   * Validate a single CSV row
   */
  private validateRow(
    row: unknown,
    rowIndex: number
  ): RowValidationResult {
    const parseResult = parseMileageCsvRow(row);

    if (!parseResult.success) {
      const errorMessages = parseResult.errors.map(e => e.message).join(', ');
      return {
        valid: false,
        error: `Row ${rowIndex}: ${errorMessages}`,
      };
    }

    const data = parseResult.data;

    // Check for future dates
    const readingDate = new Date(data.readingDate);
    const today = new Date();
    today.setHours(23, 59, 59, 999);

    if (readingDate > today) {
      return {
        valid: false,
        error: `Row ${rowIndex}: Reading date ${data.readingDate} is in the future`,
        anomaly: {
          trainNumber: data.trainNumber,
          readingDate: data.readingDate,
          type: 'FUTURE_DATE',
          value: null,
          message: `Reading date ${data.readingDate} is in the future`,
          rawReading: data.odometerKm,
        },
      };
    }

    return {
      valid: true,
      record: {
        trainNumber: data.trainNumber,
        readingDate: data.readingDate,
        odometerKm: data.odometerKm,
        rowIndex,
      },
    };
  }

  /**
   * Process a batch of records within a transaction
   */
  private async processBatch(
    batch: ParsedMileageRecord[],
    fileName: string,
    result: IngestionResult
  ): Promise<{ trainIdsUpdated: Set<string> }> {
    return this.inTransaction('processBatch', async (tx, span) => {
      span.setAttribute('batch.size', batch.length);

      const trainIdsUpdated = new Set<string>();

      for (const record of batch) {
        try {
          // Find train
          const train = await tx.query.trains.findFirst({
            where: eq(trains.trainNumber, record.trainNumber),
          });

          if (!train) {
            result.invalidRecords++;
            const anomaly: AnomalyRecord = {
              trainNumber: record.trainNumber,
              readingDate: record.readingDate,
              type: 'UNKNOWN_TRAIN',
              value: null,
              message: `Train number '${record.trainNumber}' not found in database`,
              rawReading: record.odometerKm,
            };
            result.anomalies.push(anomaly);
            recordIngestionAnomaly('UNKNOWN_TRAIN');
            continue;
          }

          // Get previous reading
          const previousReading = await tx.query.mileageReadings.findFirst({
            where: and(
              eq(mileageReadings.trainId, train.id),
              sql`${mileageReadings.readingDate} < ${record.readingDate}`
            ),
            orderBy: desc(mileageReadings.readingDate),
          });

          // Calculate adjusted value (handle meter events)
          const adjustment = await this.getMeterAdjustment(tx, train.id, record.readingDate);
          const adjustedReading = record.odometerKm + adjustment;

          // Calculate daily km
          let dailyKm: number | null = null;
          let anomalyType: AnomalyType | null = null;
          let anomalyMessage: string | null = null;

          if (previousReading) {
            dailyKm = adjustedReading - previousReading.adjustedReading;

            // Anomaly detection
            if (dailyKm < 0) {
              anomalyType = 'NEGATIVE';
              anomalyMessage = `Negative daily mileage: ${dailyKm} km (previous: ${previousReading.adjustedReading}, current: ${adjustedReading})`;

              result.anomalies.push({
                trainNumber: record.trainNumber,
                readingDate: record.readingDate,
                type: 'NEGATIVE',
                value: dailyKm,
                message: anomalyMessage,
                rawReading: record.odometerKm,
                previousReading: previousReading.adjustedReading,
              });
              recordIngestionAnomaly('NEGATIVE');
            } else if (dailyKm > SPIKE_THRESHOLD_KM) {
              anomalyType = 'SPIKE';
              anomalyMessage = `Unusually high daily mileage: ${dailyKm} km (threshold: ${SPIKE_THRESHOLD_KM})`;

              result.anomalies.push({
                trainNumber: record.trainNumber,
                readingDate: record.readingDate,
                type: 'SPIKE',
                value: dailyKm,
                message: anomalyMessage,
                rawReading: record.odometerKm,
                previousReading: previousReading.adjustedReading,
              });
              recordIngestionAnomaly('SPIKE');
            }
          }

          // Insert or update reading
          await tx
            .insert(mileageReadings)
            .values({
              trainId: train.id,
              readingDate: record.readingDate,
              rawReading: record.odometerKm,
              adjustedReading,
              dailyKm,
              validationStatus: anomalyType ? 'ANOMALY' : 'VALID',
              anomalyType: anomalyType ?? undefined,
              anomalyNotes: anomalyMessage ?? undefined,
              sourceFile: fileName,
            })
            .onConflictDoUpdate({
              target: [mileageReadings.trainId, mileageReadings.readingDate],
              set: {
                rawReading: record.odometerKm,
                adjustedReading,
                dailyKm,
                validationStatus: anomalyType ? 'ANOMALY' : 'VALID',
                anomalyType: anomalyType ?? null,
                anomalyNotes: anomalyMessage ?? null,
                sourceFile: fileName,
                ingestedAt: new Date(),
              },
            });

          result.validRecords++;
          trainIdsUpdated.add(train.id);
        } catch (error) {
          result.invalidRecords++;
          this.log.warn(
            { record, error: error instanceof Error ? error.message : 'Unknown error' },
            'Record processing failed'
          );
        }
      }

      return { trainIdsUpdated };
    });
  }

  /**
   * Get cumulative meter adjustment for a train as of a given date
   */
  private async getMeterAdjustment(
    tx: Parameters<Parameters<typeof this.inTransaction>[1]>[0],
    trainId: string,
    asOfDate: string
  ): Promise<number> {
    const events = await tx.query.meterEvents.findMany({
      where: and(
        eq(meterEvents.trainId, trainId),
        lte(meterEvents.eventDate, asOfDate)
      ),
    });

    return events.reduce((sum, e) => sum + (e.adjustmentKm ?? 0), 0);
  }

  /**
   * Update train current mileage for all affected trains
   */
  private async updateTrainMileage(
    records: ParsedMileageRecord[],
    trainIds: Set<string>
  ): Promise<void> {
    return this.traced('updateTrainMileage', async (span) => {
      span.setAttribute('trains.count', trainIds.size);

      // Group records by train, find latest reading
      const latestByTrain = new Map<string, ParsedMileageRecord>();

      for (const record of records) {
        const existing = latestByTrain.get(record.trainNumber);
        if (!existing || record.readingDate > existing.readingDate) {
          latestByTrain.set(record.trainNumber, record);
        }
      }

      // Update train current_mileage for each affected train
      for (const [trainNumber, record] of latestByTrain) {
        await this.db
          .update(trains)
          .set({
            currentMileageKm: record.odometerKm,
            updatedAt: new Date(),
          })
          .where(eq(trains.trainNumber, trainNumber));
      }

      // Update fleet mileage targets
      await this.db.execute(sql`SELECT update_fleet_mileage_targets()`);

      this.log.info(
        { trainsUpdated: latestByTrain.size },
        'Train mileages updated'
      );
    });
  }

  // ===========================================================================
  // Meter Event Management
  // ===========================================================================

  /**
   * Create a meter event (for manual corrections or detected resets)
   */
  async createMeterEvent(
    trainId: string,
    eventType: 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP',
    eventDate: string,
    oldReading: number,
    newReading: number,
    reason?: string,
    createdBy?: string
  ): Promise<MeterEventRecord> {
    return this.inTransaction('createMeterEvent', async (tx, span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);
      span.setAttribute('event.type', eventType);

      // Verify train exists
      const train = await tx.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new BusinessRuleError(`Train not found: ${trainId}`, {
          rule: 'train_exists',
          context: { trainId },
        });
      }

      // Calculate adjustment (cumulative offset to maintain mileage continuity)
      const adjustmentKm = oldReading - newReading;

      // Insert meter event
      const [event] = await tx
        .insert(meterEvents)
        .values({
          trainId,
          eventDate,
          eventType,
          oldMeterReading: oldReading,
          newMeterReading: newReading,
          adjustmentKm,
          reason,
          createdBy,
        })
        .returning();

      this.log.info(
        {
          eventId: event.id,
          trainId,
          trainNumber: train.trainNumber,
          eventType,
          oldReading,
          newReading,
          adjustmentKm,
        },
        'Meter event created'
      );

      return {
        trainNumber: train.trainNumber,
        trainId,
        eventDate,
        eventType,
        oldReading,
        newReading,
        adjustmentKm,
      };
    });
  }

  /**
   * Get meter events for a train
   */
  async getMeterEvents(trainId: string): Promise<MeterEventRecord[]> {
    return this.traced('getMeterEvents', async (span) => {
      span.setAttribute(MmsAttributes.TRAIN_ID, trainId);

      const train = await this.db.query.trains.findFirst({
        where: eq(trains.id, trainId),
      });

      if (!train) {
        throw new BusinessRuleError(`Train not found: ${trainId}`, {
          rule: 'train_exists',
          context: { trainId },
        });
      }

      const events = await this.db.query.meterEvents.findMany({
        where: eq(meterEvents.trainId, trainId),
        orderBy: desc(meterEvents.eventDate),
      });

      return events.map((e) => ({
        trainNumber: train.trainNumber,
        trainId: e.trainId,
        eventDate: e.eventDate,
        eventType: e.eventType as 'RESET' | 'REPLACEMENT' | 'CALIBRATION' | 'SWAP',
        oldReading: e.oldMeterReading ?? 0,
        newReading: e.newMeterReading ?? 0,
        adjustmentKm: e.adjustmentKm ?? 0,
      }));
    });
  }

  // ===========================================================================
  // Health Monitoring
  // ===========================================================================

  /**
   * Check file arrival health
   *
   * Returns whether files have been received within the expected timeframe.
   * Used by health check endpoints and alerting.
   */
  async checkFileArrivalHealth(): Promise<{
    healthy: boolean;
    lastFileAt: Date | null;
    hoursSinceLastFile: number | null;
    alertThresholdHours: number;
  }> {
    const alertThresholdHours = ALERT_THRESHOLD_HOURS;

    if (!this.lastFileReceivedAt) {
      return {
        healthy: true, // No baseline yet
        lastFileAt: null,
        hoursSinceLastFile: null,
        alertThresholdHours,
      };
    }

    const hoursSinceLastFile =
      (Date.now() - this.lastFileReceivedAt.getTime()) / (1000 * 60 * 60);

    const healthy = hoursSinceLastFile <= alertThresholdHours;

    return {
      healthy,
      lastFileAt: this.lastFileReceivedAt,
      hoursSinceLastFile: Math.round(hoursSinceLastFile * 10) / 10,
      alertThresholdHours,
    };
  }

  /**
   * Get ingestion statistics
   */
  async getIngestionStats(days: number = 7): Promise<{
    totalFiles: number;
    totalRecords: number;
    totalAnomalies: number;
    anomaliesByType: Record<string, number>;
    averageRecordsPerFile: number;
  }> {
    return this.traced('getIngestionStats', async (span) => {
      span.setAttribute('stats.days', days);

      const since = new Date();
      since.setDate(since.getDate() - days);

      // Get anomaly counts by type
      const anomalyStats = await this.db
        .select({
          anomalyType: mileageReadings.anomalyType,
          count: sql<number>`count(*)::int`,
        })
        .from(mileageReadings)
        .where(
          and(
            eq(mileageReadings.validationStatus, 'ANOMALY'),
            sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`
          )
        )
        .groupBy(mileageReadings.anomalyType);

      const anomaliesByType: Record<string, number> = {};
      let totalAnomalies = 0;

      for (const stat of anomalyStats) {
        const type = stat.anomalyType ?? 'UNKNOWN';
        anomaliesByType[type] = stat.count;
        totalAnomalies += stat.count;
      }

      // Get total records count
      const [recordStats] = await this.db
        .select({
          total: sql<number>`count(*)::int`,
          files: sql<number>`count(distinct ${mileageReadings.sourceFile})::int`,
        })
        .from(mileageReadings)
        .where(sql`${mileageReadings.ingestedAt} >= ${since.toISOString()}`);

      const totalRecords = recordStats?.total ?? 0;
      const totalFiles = recordStats?.files ?? 0;

      return {
        totalFiles,
        totalRecords,
        totalAnomalies,
        anomaliesByType,
        averageRecordsPerFile: totalFiles > 0 ? Math.round(totalRecords / totalFiles) : 0,
      };
    });
  }

  // ===========================================================================
  // Query Methods (for API endpoints)
  // ===========================================================================

  /**
   * Get mileage readings with filtering
   *
   * Supports filtering by trainId, date range, and validation status.
   * Returns readings with train information for API responses.
   */
  async getMileageReadings(filters: MileageReadingFilters): Promise<{
    data: MileageReadingWithTrain[];
    total: number;
  }> {
    return this.traced('getMileageReadings', async (span) => {
      span.setAttribute('filters.trainId', filters.trainId ?? 'all');
      span.setAttribute('filters.fromDate', filters.fromDate ?? 'none');
      span.setAttribute('filters.toDate', filters.toDate ?? 'none');

      const conditions: ReturnType<typeof eq>[] = [];

      if (filters.trainId) {
        conditions.push(eq(mileageReadings.trainId, filters.trainId));
      }

      if (filters.fromDate) {
        conditions.push(sql`${mileageReadings.readingDate} >= ${filters.fromDate}`);
      }

      if (filters.toDate) {
        conditions.push(sql`${mileageReadings.readingDate} <= ${filters.toDate}`);
      }

      if (filters.validationStatus) {
        conditions.push(eq(mileageReadings.validationStatus, filters.validationStatus));
      }

      // Build where clause
      const whereClause = conditions.length > 0 ? and(...conditions) : undefined;

      // Get total count
      const [countResult] = await this.db
        .select({ count: sql<number>`count(*)::int` })
        .from(mileageReadings)
        .where(whereClause);

      const total = countResult?.count ?? 0;

      // Get paginated readings with train info
      const page = filters.page ?? 1;
      const pageSize = Math.min(200, Math.max(1, filters.pageSize ?? 50));
      const offset = (page - 1) * pageSize;

      const readings = await this.db
        .select({
          trainId: mileageReadings.trainId,
          trainNumber: trains.trainNumber,
          readingDate: mileageReadings.readingDate,
          rawReading: mileageReadings.rawReading,
          adjustedReading: mileageReadings.adjustedReading,
          dailyKm: mileageReadings.dailyKm,
          validationStatus: mileageReadings.validationStatus,
          sourceFile: mileageReadings.sourceFile,
        })
        .from(mileageReadings)
        .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
        .where(whereClause)
        .orderBy(desc(mileageReadings.readingDate))
        .limit(pageSize)
        .offset(offset);

      return {
        data: readings.map((r) => ({
          trainId: r.trainId,
          trainNumber: r.trainNumber,
          readingDate: r.readingDate,
          rawReading: r.rawReading,
          adjustedReading: r.adjustedReading,
          dailyKm: r.dailyKm,
          validationStatus: r.validationStatus as 'PENDING' | 'VALID' | 'ANOMALY' | 'CORRECTED',
          sourceFile: r.sourceFile,
        })),
        total,
      };
    });
  }

  /**
   * Get mileage anomalies requiring review
   *
   * Returns anomalies (SPIKE, NEGATIVE, etc.) with details
   * for investigation and correction.
   */
  async getAnomalies(filters: AnomalyQueryFilters): Promise<{
    data: AnomalyWithDetails[];
    total: number;
  }> {
    return this.traced('getAnomalies', async (span) => {
      span.setAttribute('filters.trainId', filters.trainId ?? 'all');

      const conditions: ReturnType<typeof eq>[] = [
        eq(mileageReadings.validationStatus, 'ANOMALY'),
      ];

      if (filters.trainId) {
        conditions.push(eq(mileageReadings.trainId, filters.trainId));
      }

      if (filters.fromDate) {
        conditions.push(sql`${mileageReadings.readingDate} >= ${filters.fromDate}`);
      }

      if (filters.toDate) {
        conditions.push(sql`${mileageReadings.readingDate} <= ${filters.toDate}`);
      }

      if (filters.anomalyType) {
        conditions.push(eq(mileageReadings.anomalyType, filters.anomalyType));
      }

      const whereClause = and(...conditions);

      // Get total count
      const [countResult] = await this.db
        .select({ count: sql<number>`count(*)::int` })
        .from(mileageReadings)
        .where(whereClause);

      const total = countResult?.count ?? 0;

      // Get paginated anomalies
      const page = filters.page ?? 1;
      const pageSize = Math.min(200, Math.max(1, filters.pageSize ?? 50));
      const offset = (page - 1) * pageSize;

      const anomalies = await this.db
        .select({
          trainId: mileageReadings.trainId,
          trainNumber: trains.trainNumber,
          readingDate: mileageReadings.readingDate,
          anomalyType: mileageReadings.anomalyType,
          rawReading: mileageReadings.rawReading,
          dailyKm: mileageReadings.dailyKm,
          anomalyNotes: mileageReadings.anomalyNotes,
          sourceFile: mileageReadings.sourceFile,
        })
        .from(mileageReadings)
        .innerJoin(trains, eq(mileageReadings.trainId, trains.id))
        .where(whereClause)
        .orderBy(desc(mileageReadings.readingDate))
        .limit(pageSize)
        .offset(offset);

      // Calculate expected range for each anomaly
      const results: AnomalyWithDetails[] = anomalies.map((a) => {
        // Default expected range based on typical daily km
        const expectedRange = {
          min: 0,
          max: SPIKE_THRESHOLD_KM,
        };

        // Suggest action based on anomaly type
        let suggestedAction = 'Review reading and verify data source';
        switch (a.anomalyType) {
          case 'NEGATIVE':
            suggestedAction = 'Check for meter event (reset/replacement) or data entry error';
            break;
          case 'SPIKE':
            suggestedAction = 'Verify odometer reading or check for meter event';
            break;
          case 'DUPLICATE':
            suggestedAction = 'Confirm which reading is correct and remove duplicate';
            break;
          case 'MISSING':
            suggestedAction = 'Check source file for missing train data';
            break;
        }

        return {
          trainId: a.trainId,
          trainNumber: a.trainNumber,
          readingDate: a.readingDate,
          anomalyType: a.anomalyType as DbAnomalyType | null,
          rawReading: a.rawReading,
          dailyKm: a.dailyKm,
          expectedRange,
          suggestedAction,
        };
      });

      return { data: results, total };
    });
  }

  // ===========================================================================
  // Utility Methods
  // ===========================================================================

  /**
   * Split array into chunks
   */
  private chunk<T>(array: T[], size: number): T[][] {
    const chunks: T[][] = [];
    for (let i = 0; i < array.length; i += size) {
      chunks.push(array.slice(i, i + size));
    }
    return chunks;
  }
}

// =============================================================================
// Singleton Export
// =============================================================================

let ingestionServiceInstance: IngestionService | null = null;

export function getIngestionService(): IngestionService {
  if (!ingestionServiceInstance) {
    ingestionServiceInstance = new IngestionService();
  }
  return ingestionServiceInstance;
}

export default IngestionService;

