/**
 * MMS PM Scheduler Service - Tactical PM Scheduling
 *
 * Schedules preventive maintenance within a 12-week horizon, respecting:
 * - Compliance windows (mileage OR time triggers)
 * - PM hierarchy (C4 satisfies C1/C2/C3)
 * - Track capability requirements
 * - Material constraints (hard 14 days, soft 90 days)
 * - Labor capacity (depot man-hour availability)
 * - Maximo lock status (INPRG work orders are read-only)
 * - Service demand (fleet availability)
 *
 * Key business rules:
 * - Compliance window: ±10% of interval (mileage or months)
 * - PM hierarchy: Higher-level PMs satisfy lower-level requirements
 * - Material hard constraint: BLOCKING parts must be available within 14 days
 * - Material soft constraint: Warning if parts unavailable within 90 days
 * - Labor capacity: PM hours must fit within weekly depot capacity
 * - Track utilization target: 85%
 * - Maximo lock: Cannot modify PM with INPRG work order
 *
 * @see specs/003-database-schema.md Section 3.5 (PM Management)
 * @see specs/004-domain-services.md Section 4.4 (PM Scheduler)
 */

import { eq, and, sql, desc, inArray, gte, lte, isNull, count } from 'drizzle-orm';
import type { SQL } from 'drizzle-orm';
import { BaseService, MmsAttributes } from '../lib/services/base';
import {
  pmSchedule,
  pmTypes,
  pmMaterialRequirements,
  trains,
  tracks,
  trackCapabilities,
  pmCapabilityRequirements,
  inventoryPositions,
  materialReservations,
  pmScheduleHistory,
  mileageReadings,
  type PmScheduleRecord,
  type NewPmScheduleRecord,
  type PmType,
  type Train,
  type Track,
  type NewPmScheduleHistory,
} from '../lib/db/schema';
import {
  NotFoundError,
  PmScheduleNotFoundError,
  TrainNotFoundError,
  MaximoLockError,
  ComplianceWindowError,
  TrackConflictError,
  MaterialConstraintError,
  ServiceDemandViolationError,
  LaborCapacityError,
  ValidationError,
  BusinessRuleError,
} from '../lib/errors';
import { getServiceDemandService } from './service-demand';
import { getUnavailabilityService } from './unavailability';
import { getManHourLevelingService, type LaborCapacityResult } from './man-hour-leveling';

// =============================================================================
// Types
// =============================================================================

/** Track type values */
type TrackType = 'LIGHT' | 'HEAVY' | 'OVERHAUL' | 'STABLING';

/** Material criticality values */
type MaterialCriticality = 'BLOCKING' | 'DEFERRABLE' | 'CONSUMABLE';

/** Reservation type values */
type ReservationType = 'SOFT' | 'HARD';

/** PM due calculation result */
export interface PmDueResult {
  pmTypeId: string;
  pmCode: string;
  pmName: string;
  trainId: string;
  trainNumber: string;
  fleetId: string;
  dueMileageKm: number | null;
  dueDate: string | null;
  currentMileageKm: number;
  kmUntilDue: number | null;
  daysUntilDue: number | null;
  triggerType: 'MILEAGE' | 'TIME' | 'BOTH';
  complianceWindow: ComplianceWindow;
  isOverdue: boolean;
  lastPmDate: string | null;
  lastPmMileageKm: number | null;
}

/** Compliance window for scheduling */
export interface ComplianceWindow {
  startDate: string;

/**
 * MMS Man-hour Leveling Service
 *
 * Projects workforce requirements and generates adjustment recommendations
 * to balance workload across time periods. Prevents overload/underutilization
 * of depot maintenance resources over the tactical planning horizon.
 *
 * Key responsibilities:
 * - Calculate raw man-hour projections from PM schedule
 * - Identify overloaded and underutilized weeks
 * - Apply leveling strategies in priority order
 * - Persist projections and adjustments
 * - Support approval workflow for adjustments
 *
 * Leveling Strategies (priority order):
 * 1. ADVANCE_PM (1.1x cost, LOW risk, max 40h/week)
 * 2. DEFER_PM (1.05x cost, LOW risk, max 40h/week)
 * 3. ADD_OVERTIME (1.5x cost, NO risk, max 80h/week)
 * 4. CROSS_DEPOT (1.3x cost, MEDIUM risk, max 60h/week)
 * 5. ADD_CONTRACTOR (2.0x cost, MEDIUM risk, max 100h/week)
 * 6. MANUAL_REVIEW (flagged for high unresolvable overload)
 *
 * Utilization Targets:
 * - Target: 85%
 * - Minimum: 70% (underutilized below this)
 * - Maximum: 100% (overloaded above this)
 *
 * @see specs/004-domain-services.md Section 4.6
 */

import {
  eq,
  and,
  gte,
  lte,
  desc,
  asc,
  sql,
  inArray,
  isNull,
  or,
  count,
  type SQL,
} from 'drizzle-orm';
import {
  addDays,
  addWeeks,
  startOfWeek,
  endOfWeek,
  format,
  differenceInWeeks,
  parseISO,
  isBefore,
  isAfter,
} from 'date-fns';
import { BaseService } from '../lib/services/base';
import {
  manhourCapacity,
  manhourProjections,
  manhourAdjustments,
  pmSchedule,
  pmTypes,
  depots,
  trains,
  laborRates,
  type ManhourCapacity,
  type ManhourProjection,
  type ManhourAdjustment,
} from '../lib/db/schema';
import { NotFoundError, ValidationError, ConflictError } from '../lib/errors';

// =============================================================================
// Constants
// =============================================================================

/** Minimum utilization percentage (underutilized below this) */
const MIN_UTILIZATION = 0.7;

/** Maximum utilization percentage (overloaded above this) */
const MAX_UTILIZATION = 1.0;

/** Default base labor rate per hour (SGD) */
const DEFAULT_BASE_RATE = 85;

/** Minimum meaningful shift in hours (don't bother with tiny adjustments) */
const MIN_SHIFT_HOURS = 8;

/** Minimum overtime hours to add */
const MIN_OVERTIME_HOURS = 4;

// =============================================================================
// Types
// =============================================================================

/** Leveling strategy types */
export type AdjustmentType =
  | 'ADVANCE_PM'
  | 'DEFER_PM'
  | 'ADD_OVERTIME'
  | 'CROSS_DEPOT'

/**
 * MMS Notification Service
 *
 * Handles email notifications with:
 * - Per-user notification preferences
 * - Digest modes (IMMEDIATE, DAILY_DIGEST, WEEKLY_DIGEST)
 * - Template rendering with variable interpolation
 * - SMTP delivery with retry logic
